/* techniques q20 (114 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q20"]=window.__LIBQ["tien-nghich"]["q20"]||{};window.__LIBQ["tien-nghich"]["q20"]["techniques"]={"updatedAt":"2026-07-17","count":114,"techniques":[{"id":"phan-co-dai-phap","name":"Phản Cổ đại pháp","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Tiên Hoàng huyết mạch","soHuu":["Tiên Hoàng","Minh Đạo Tôn"],"blurb":"Phản Cổ đại pháp là thuật pháp được Tiên Hoàng dùng trên Minh Đạo Tôn trong ao nước đen. Nó liên quan đến việc mưu cầu huyết mạch Tiên Tổ và khả năng Phản Cổ, còn thành bại tùy thuộc oán hận của người tu.","detail":"Trong địa cung dưới đáy ao hoàng thành Trung Châu, Tiên Hoàng để Minh Đạo Tôn chịu hắc khí trong ao nước đen xâm nhập thân thể nhằm thay đổi huyết mạch. Tiên Hoàng nói Minh Đạo Tôn tu hành ở nơi này có thể có được huyết mạch, nhưng muốn Phản Cổ thì phải dựa vào oán hận của chính hắn.","thuocTinh":"huyết mạch, Phản Cổ","nguonGoc":"Tiên Hoàng dùng trong địa cung dưới đáy ao hoàng thành","congNang":["Giúp người tu có cơ hội đạt huyết mạch Tiên Tổ và Phản Cổ khi oán hận đủ mạnh @c1866"],"nguoiTu":[{"ten":"Minh Đạo Tôn","tuChuong":"@c1866","tangDatToi":"đang tu hành trong ao nước đen","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1866","loai":"xuất hiện","importance":"normal","giaiDoan":"Minh Đạo Tôn tu hành trong ao nước đen","text":"Tiên Hoàng dùng Phản Cổ đại pháp trên Minh Đạo Tôn để mưu cầu huyết mạch Tiên Tổ và khả năng Phản Cổ.","anchor":"Ngươi tu hành ở nơi này có thể có được huyết mạch"}]},"capNhatToi":"@c1866","nguon":["@c1866"]},{"id":"dung-hon-that","name":"Dung hồn thật","cn":"","loai":"than-thong","loaiLabel":"Thần thông dung hồn","phamCap":"không rõ","hePhai":"Song Tử Đại Thiên Tôn","soHuu":["Song Tử Đại Thiên Tôn"],"blurb":"Thần thông từng được Song Tử Đại Thiên Tôn thi triển để khôi phục ký ức Tổ Thành cho Vương Lâm.","detail":"Trước chuyến đi Tổ Thành, Song Tử Đại Thiên Tôn từng thi triển dung hồn thật, lấy lại một phần ký ức về Tổ Thành cho Vương Lâm.","congNang":["Lấy lại một phần ký ức về Tổ Thành cho người được thi triển @c1867"],"nguoiTu":[{"ten":"Song Tử Đại Thiên Tôn","tuChuong":"@c1867","tangDatToi":"đã thi triển","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1867","loai":"nhắc tới","importance":"normal","giaiDoan":"Ký ức Tổ Thành","text":"Dung hồn thật được nhắc là thuật Song Tử Đại Thiên Tôn từng dùng để lấy lại một phần ký ức Tổ Thành cho Vương Lâm.","anchor":"Song Tử Đại Thiên Tôn thi triển dung hồn thật, lấy lại một phần ký ức về Tổ Thành cho hắn"}]},"capNhatToi":"@c1867","nguon":["@c1867"]},{"id":"luan-hoi-bon-nguyen","name":"Luân hồi bổn nguyên","cn":"","loai":"cong-phap","loaiLabel":"Bổn nguyên hư","phamCap":"bổn nguyên","hePhai":"hư bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Luân hồi bổn nguyên là bổn nguyên thứ tư thuộc hệ hư của Vương Lâm, được hiểu ra một tia tại Đông Lâm Tông, tiếp nối sau sinh tử, nhân quả và chân giả bổn nguyên.","detail":"Sau khi đã nắm được sinh tử, nhân quả và chân giả bổn nguyên, Vương Lâm tại Đông Lâm Tông cảm ngộ thêm một tia về luân hồi bổn nguyên — bổn nguyên thứ tư trong hệ hư của mình. Hiện tại bổn nguyên này mới chỉ vừa mở ra như một cánh cửa mới, chưa đại thành, còn cần cảm ngộ sâu hơn.","thuocTinh":"luân hồi","uyLuc":"Mới mở ra một tia, chưa đại thành.","dacDiem":"Thuộc hệ hư bổn nguyên của Vương Lâm.","congNang":["Mở ra hướng cảm ngộ luân hồi trong hệ hư bổn nguyên của Vương Lâm @c1867"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1867","tangDatToi":"một tia","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1867","loai":"xuất hiện","importance":"major","giaiDoan":"Mới hiểu một tia","text":"Vương Lâm ở Đông Lâm Tông hiểu thêm bổn nguyên thứ tư là luân hồi, hiện chỉ mới có một tia.","anchor":"sau đó Vương Lâm ở Đông Lâm Tông lại hiểu thêm bổn nguyên thứ tư là luân hồi"}]},"capNhatToi":"@c1867","nguon":["@c1867"]},{"id":"moc-bon-nguyen","name":"Mộc bổn nguyên","cn":"","loai":"cong-phap","loaiLabel":"Bổn nguyên ngũ hành","phamCap":"bổn nguyên","hePhai":"ngũ hành","soHuu":["Vương Lâm"],"blurb":"Một trong ngũ hành bổn nguyên của Vương Lâm, ở Tử Dương Tông đã đại thành gần mức ngưng tụ bổn nguyên chân thân.","detail":"Một năm cảm nhận khí tức quê hương tại Tử Dương Tông khiến mộc bổn nguyên trong cơ thể Vương Lâm đại thành, chỉ còn cách cấp độ ngưng tụ bổn nguyên chân thân một đoạn.","thuocTinh":"mộc","uyLuc":"Đại thành, gần cấp độ ngưng tụ bổn nguyên chân thân.","dacDiem":"Thuộc ngũ hành bổn nguyên của Vương Lâm.","congNang":["Là một phần trong quá trình hoàn thiện ngũ hành bổn nguyên và ngũ hành chân thân của Vương Lâm @c1867"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1867","tangDatToi":"đại thành","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1867","loai":"có người đại thành","importance":"normal","giaiDoan":"Đại thành","text":"Mộc bổn nguyên trong cơ thể Vương Lâm đại thành, gần tới cấp độ ngưng tụ bổn nguyên chân thân.","anchor":"khiến cho mộc bổn nguyên trong cơ thể đại thành, khoảng cách tới cấp độ ngưng tụ bổn nguyên chân thân"}]},"capNhatToi":"@c1867","nguon":["@c1867"]},{"id":"thuat-huyen-dong","name":"Thuật huyễn động","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Lý Phủ","soHuu":["Tu sĩ Lý gia huyết ảnh"],"blurb":"Thuật độn thoát được tu sĩ Lý gia huyết ảnh thi triển khi bị Vương Lâm áp đảo. Khi dùng, hắn phun máu và hóa thành hồng ảnh bay xa ngàn dặm.","detail":"Trong cuộc tập kích Vương Lâm ở Đông Thành, tu sĩ Lý gia huyết ảnh nhận ra toàn lực Kim Tôn của mình bị hóa giải dễ dàng nên lập tức dùng thuật huyễn động để bỏ chạy. Thuật này biểu hiện bằng việc phun máu, trong nháy mắt hóa thành một đạo hồng ảnh và thoát đi rất xa.","thuocTinh":"độn thoát bằng huyết ảnh","uyLuc":"Có thể giúp người thi triển hóa hồng ảnh bay xa ngàn dặm trong nháy mắt.","dacDiem":"Gắn với tình huống bỏ chạy khẩn cấp sau khi bị áp đảo.","congNang":["Độn thoát bằng huyết ảnh, giúp người thi triển trong nháy mắt bay xa ngàn dặm @c1868"],"nguoiTu":[{"ten":"Tu sĩ Lý gia huyết ảnh","tuChuong":"@c1868","tangDatToi":"không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1868","loai":"thi triển","importance":"normal","giaiDoan":"Độn thoát khỏi Vương Lâm","text":"Tu sĩ Lý gia huyết ảnh phun máu thi triển thuật huyễn động, hóa thành hồng ảnh bay xa ngàn dặm sau khi tập kích thất bại.","anchor":"thi triển thuật huyễn động, trong nháy mắt hóa thành một đạo hồng ảnh"}]},"capNhatToi":"@c1868","nguon":["@c1868"]},{"id":"cam-che-va-phong-an-nha-tro-dong-thanh","name":"Cấm chế và phong ấn nhà trọ Đông Thành","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế trận pháp","phamCap":"không rõ","hePhai":"Nhà trọ Đông Thành","soHuu":[],"blurb":"Hệ thống cấm chế và phong ấn bố trí trong gian phòng Vương Lâm thuê tại Đông Thành. Khi mở ra, căn phòng trở thành nơi thích hợp để bế quan.","detail":"Trong nhà trọ nhiều tầng ở Đông Thành, gian phòng nhỏ Vương Lâm thuê có tiên khí nồng đậm, trên vách tường bốn phía tồn tại nhiều cấm chế và phong ấn. Các bố trí này tự động mở ra, giúp căn phòng trở thành nơi bế quan tốt.","thuocTinh":"phòng hộ và hỗ trợ bế quan","uyLuc":"Biến gian phòng thuê thành nơi bế quan có tiên khí nồng đậm và phòng hộ bằng cấm chế, phong ấn.","dacDiem":"Tự động mở ra trong gian phòng nhà trọ.","congNang":["Phòng hộ và tạo môi trường bế quan trong gian phòng nhà trọ Đông Thành @c1868"],"tabs":{"tienTrinh":[{"chuong":"@c1868","loai":"xuất hiện","importance":"normal","giaiDoan":"Phòng nhà trọ","text":"Cấm chế và phong ấn trên vách tường gian phòng Vương Lâm thuê tự động mở ra, khiến nơi này trở thành chỗ bế quan tốt.","anchor":"trên vách tường bốn phía ở đây cũng tồn tại rất nhiều cấm chế và phong ấn"}]},"capNhatToi":"@c1868","nguon":["@c1868"]},{"id":"tien-tran-ly-phu","name":"Tiễn trận Lý Phủ","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Lý Phủ","soHuu":["Mấy trăm người Lý Phủ"],"blurb":"Trận pháp công kích hợp lực bằng cung tiễn của Lý Phủ. Mấy trăm mũi tên tạo thành mưa tên, phía sau hiện đồ án trận pháp và bộc phát sát khí.","detail":"Tiễn trận được phát động khi Vương Lâm bước vào Lý Phủ. Nhiều người trong phủ đồng loạt kéo cung, mưa tên kết hợp đồ án trận pháp lao tới, nhưng bị chưởng ấn của Vương Lâm đánh sụp.","thuocTinh":"cung tiễn, trận pháp","uyLuc":"Có thể uy hiếp Thiên Tôn thường nhưng bị Vương Lâm phá trong một lần phất tay.","dacDiem":"Dựa vào nhiều người cùng phát tiễn để hình thành mưa tên và đồ án trận pháp.","congNang":["Công kích hợp lực bằng mưa tên có trận pháp sát khí @c1869"],"trangThai":"bị phá giải","capNhatToi":"@c1869","tabs":{"tienTrinh":[{"chuong":"@c1869","loai":"thi triển","importance":"normal","giaiDoan":"Phát động trong Lý Phủ","text":"Mấy trăm người Lý Phủ đồng loạt bắn tên tạo thành mưa tên có đồ án trận pháp, nhưng bị chưởng ấn của Vương Lâm phá tan.","anchor":"Phía sau mơ hồ hiện ra một đồ án trận pháp"}]},"dinhDanh":"goc","nguon":["@c1869"]},{"id":"chin-tien-tran-ly-phu","name":"Chín tiễn trận Lý Phủ","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Lý Phủ","soHuu":["Lý Phủ"],"blurb":"Trận pháp phát tiễn từ chín vị trí trong Lý Phủ. Chín mũi tên nổ thành nhiều mũi tên, hợp thành cuồng phong và bàn tay khổng lồ chụp xuống.","detail":"Sau tiễn trận đầu, chín vị trí trong Lý Phủ đồng thời bắn ra chín mũi tên. Mỗi mũi tên lại hóa ra nhiều mũi tên, uy lực gấp nhiều lần lượt đầu và hình thành bàn tay khổng lồ, nhưng bị một chỉ của Vương Lâm định trụ trước mặt.","thuocTinh":"cung tiễn, trận pháp","uyLuc":"Được mô tả có thể so với chín lần tiễn trận trước.","dacDiem":"Chín điểm phát tiễn cùng lúc, mỗi mũi tên mở rộng thành mưa tên dày đặc.","congNang":["Chín điểm phát tiễn mở rộng thành mưa tên và hóa bàn tay khổng lồ @c1869"],"trangThai":"bị định trụ","capNhatToi":"@c1869","tabs":{"tienTrinh":[{"chuong":"@c1869","loai":"thi triển","importance":"normal","giaiDoan":"Chín vị trí phát tiễn","text":"Chín mũi tên từ Lý Phủ đồng thời bắn ra, hóa thành mưa tên và bàn tay khổng lồ, rồi bị một chỉ của Vương Lâm làm dừng lại.","anchor":"Chín mũi tên đồng thời b*n r* có thể so với chín lần tiễn trận vừa rồi"}]},"dinhDanh":"goc","nguon":["@c1869"]},{"id":"chuong-an-cua-vuong-lam","name":"Chưởng ấn của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông chưởng ấn do Vương Lâm phất tay tạo ra khi xông vào Lý Phủ. Chưởng ấn chân thật, vân tay rõ ràng, trực tiếp đánh sụp tiễn trận đầu.","detail":"Vương Lâm phất tay, hóa ra một chưởng ấn cực kỳ chân thật để đối kháng mưa tên của Lý Phủ. Chưởng ấn va chạm với tiễn trận, khiến mưa tên sụp đổ trong tiếng nổ vang trời.","thuocTinh":"chưởng pháp, tiên lực","uyLuc":"Đủ phá công kích được mô tả ngang sức tầng sáu Thiên Tôn.","dacDiem":"Chưởng ấn có vân tay rõ ràng như thật.","congNang":["Phá mưa tên và trận pháp công kích hợp lực @c1869"],"trangThai":"đã thi triển","capNhatToi":"@c1869","tabs":{"tienTrinh":[{"chuong":"@c1869","loai":"thi triển","importance":"normal","giaiDoan":"Phá tiễn trận đầu","text":"Vương Lâm phất tay tạo chưởng ấn chân thật đánh vào mưa tên, làm tiễn trận đầu của Lý Phủ sụp đổ.","anchor":"Chưởng ấn này cực kỳ chân thật, từng đường vân tay vô cùng rõ ràng"}]},"dinhDanh":"goc","nguon":["@c1869"]},{"id":"mot-chi-dinh-tru-mua-ten","name":"Một chỉ định trụ mưa tên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông một chỉ của Vương Lâm dùng để khống chế chín tiễn trận. Một chỉ điểm ra khiến bàn tay khổng lồ do mưa tên hóa thành đứng yên trước mặt.","detail":"Khi chín tiễn trận hóa thành bàn tay khổng lồ chụp tới, Vương Lâm điểm một chỉ. Một chỉ này khiến thiên địa như dừng lại, toàn bộ mưa tên bị định trụ trước mặt hắn.","thuocTinh":"định trụ, khống chế","uyLuc":"Khống chế được chín tiễn trận của Lý Phủ.","dacDiem":"Tạo cảm giác thiên địa vạn vật đều dừng lại trong khoảnh khắc.","congNang":["Định trụ công kích mưa tên đang lao tới @c1869"],"trangThai":"đã thi triển","capNhatToi":"@c1869","tabs":{"tienTrinh":[{"chuong":"@c1869","loai":"thi triển","importance":"normal","giaiDoan":"Định trụ chín tiễn trận","text":"Vương Lâm điểm một chỉ khiến bàn tay khổng lồ do mưa tên huyễn hóa đứng lại trước mặt.","anchor":"Một chỉ này khiến thiên địa vạn vật đều dừng lại"}]},"dinhDanh":"goc","nguon":["@c1869"]},{"id":"tien-cuc-kiem-tran-ap","name":"Tiên Cực Kiếm trấn áp","cn":"","loai":"than-thong","loaiLabel":"Thần thông/uy áp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Kim quang trong mắt Vương Lâm mang oai nghiêm của Tiên Cực Kiếm, hóa thành lực trấn áp thiên địa vạn vật.","detail":"Tại Lý Phủ, Vương Lâm vận kim quang trong hai mắt, khiến uy áp của Tiên Cực Kiếm hiện ra như lực lượng trấn áp. Lực này phá hủy cung của tộc nhân Lý Phủ, làm cung của chín Thiên Tôn vỡ vụn, bẻ gãy cung của hai Thiên Tôn tầng bảy và khiến dây cung của Dược Thiên Tôn Lý Phủ đứt thành tro bụi.","nguon":["@c1870"]},{"id":"tien-dao-ly-gia","name":"Tiễn Đạo Lý gia","cn":"","loai":"khac","loaiLabel":"Tiễn đạo/truyền thừa","phamCap":"","hePhai":"Lý Phủ","soHuu":["Lý Phủ"],"blurb":"Tiễn Đạo do lão tổ Lý gia lưu lại trong Tiễn Các, được Lý Phủ mở cho Vương Lâm tùy ý xem xét.","detail":"Sau khi hóa giải xung đột vì cung lão tổ, lão tổ Lý gia dùng việc cho phép Vương Lâm vào Tiễn Các xem Tiễn Đạo để bù lỗi. Vương Lâm sau đó lưu lại Lý Phủ, ở trong Tiễn Các nghiên cứu Tiễn Đạo của Lý gia trong thời gian chờ đại lễ sắc phong.","nguon":["@c1870"]},{"id":"thong-dao-cuu-mon-khao-nghiem","name":"Thông đạo cửu môn khảo nghiệm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp nghi thức","phamCap":"không rõ","hePhai":"Hoàng cung Tiên Tộc","soHuu":["Hoàng cung Tiên Tộc"],"blurb":"Thông đạo do hắc quang từ cửu môn nối lại trong lễ sắc phong Dược Thiên Tôn. Lần này nó dùng sát khí của hắc giáp cấm binh để khảo nghiệm Vương Lâm.","detail":"Chín đại môn màu đen tỏa hắc quang rồi nối thành một con đường thẳng trước sân rộng Tiên Đạo Điện. Khi Vương Lâm bước vào, thông đạo không khảo nghiệm tu vi mà dùng sát khí cả đời của mười vạn hắc giáp cấm binh tạo uy áp, sau đó bị Vương Lâm đánh tan phần hắc quang còn lại.","congNang":["Khảo nghiệm sát khí trước lễ sắc phong Dược Thiên Tôn @c1871"],"trangThai":"bị Vương Lâm đánh tan hắc quang trong lễ sắc phong","capNhatToi":"@c1871","tabs":{"tienTrinh":[{"chuong":"@c1871","loai":"xuất hiện","importance":"normal","giaiDoan":"Lễ sắc phong Dược Thiên Tôn","text":"Cửu môn tỏa hắc quang nối thành thông đạo khảo nghiệm, dùng sát khí của hắc giáp cấm binh ép lên Vương Lâm rồi bị hắn phá tan.","anchor":"Cửu môn lập tức tỏa ra hắc quang quỷ dị, sau khi nồng đậm tới một mức độ nhất định liền khuếch tán ra"}]},"nguon":["@c1871"]},{"id":"tran-phap-cua-hoang-cung","name":"Trận pháp của hoàng cung","cn":"","aliases":["Trận pháp hoàng cung"],"loai":"khac","loaiLabel":"Trận pháp truyền chiếu","phamCap":"không rõ","hePhai":"Hoàng cung Tiên Tộc","soHuu":["Hoàng cung Tiên Tộc"],"blurb":"Trận pháp trong hoàng cung Tiên Tộc dùng để truyền chiếu diễn biến lễ sắc phong. Hành động của Vương Lâm bên ngoài Tiên Đạo Điện được chiếu tới các tông môn trong bảy mươi hai châu.","detail":"Trong lễ sắc phong, trận pháp này khiến toàn bộ hành động của Vương Lâm ngoài Tiên Đạo Điện được các tông môn thuộc bảy mươi hai châu Tiên Tộc nhận được, biến khảo nghiệm cửu môn thành sự kiện được chứng kiến rộng khắp.","congNang":["Truyền chiếu hành động bên ngoài Tiên Đạo Điện tới các tông môn trong bảy mươi hai châu Tiên Tộc @c1871"],"capNhatToi":"@c1871","tabs":{"tienTrinh":[{"chuong":"@c1871","loai":"xuất hiện","importance":"normal","giaiDoan":"Truyền chiếu lễ sắc phong","text":"Trận pháp hoàng cung truyền chiếu toàn bộ hành động của Vương Lâm trước Tiên Đạo Điện tới các tông môn trong bảy mươi hai châu Tiên Tộc.","anchor":"tất cả hành động của ngươi ở bên ngoài Tiên Đạo Điện đều đã được trận pháp của hoàng cung chiếu ra"}]},"nguon":["@c1871"]},{"id":"than-thong-hien-te-tinh-mang-cua-hac-giap-cam-binh","name":"Thần thông hiến tế tính mạng của hắc giáp cấm binh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông quân trận","phamCap":"không rõ","hePhai":"Hoàng tộc Tiên Tộc","soHuu":["Hắc giáp cấm binh"],"blurb":"Thần thông của hắc giáp cấm binh, lấy hiến tế tính mạng để hóa thành lực sát thương kinh khủng. Chương này chỉ hé lộ công năng, chưa nói chi tiết cách thi triển.","detail":"Mười vạn hắc giáp cấm binh thuộc hoàng tộc được nói nắm giữ loại thần thông hiến tế tính mạng, có thể biến thành lực sát thương kinh khủng. Nó gắn với tính chất đáng sợ của lực lượng cấm binh chỉ phục vụ Tiên Hoàng.","congNang":["Hiến tế tính mạng để tạo lực sát thương kinh khủng @c1871"],"capNhatToi":"@c1871","tabs":{"tienTrinh":[{"chuong":"@c1871","loai":"nhắc tới","importance":"normal","giaiDoan":"Giới thiệu hắc giáp cấm binh","text":"Hắc giáp cấm binh được giới thiệu là nắm giữ thần thông hiến tế tính mạng để đổi lấy lực sát thương kinh khủng.","anchor":"mười vạn người này lại lắm giữ một loại thần thông hiến tế tính mạng biến thành lực sát thương kinh khủng"}]},"nguon":["@c1871"]},{"id":"huyet-te-tien","name":"Huyết tế tiên","aliases":["mở tiên đạo"],"loai":"khac","loaiLabel":"Nghi thức-trận pháp","phamCap":"không rõ","hePhai":"Hoàng cung Tiên Tộc","soHuu":["Thượng Huyền Đạo","Tiên Hoàng"],"blurb":"Huyết tế tiên là nghi thức do Thượng Huyền Đạo chủ trì trong đại lễ sắc phong. Nghi thức dùng huyết tế chín mươi chín thú để mở tiên đạo, dẫn sinh linh thiên ngoại tới cho Tiên Hoàng luyện thành bảo vật ban thưởng.","detail":"Trong đại lễ sắc phong trước Tiên Đạo Điện, Thượng Huyền Đạo điểm một chỉ lên trời, khiến chín mươi chín huyết trụ từ hoàng cung phóng lên cùng thú hồn, bầu trời hóa màu máu và mở ra cánh cửa hư vô. Sinh linh thiên ngoại bị dẫn tới sẽ do Tiên Hoàng đánh chết, máu vẩy xuống đất, hồn phách luyện hóa thành bảo vật ban cho người được sắc phong.","thuocTinh":"huyết tế, dẫn sinh linh thiên ngoại","congNang":["Mở tiên đạo và dẫn sinh linh thiên ngoại phục vụ đại lễ sắc phong @c1872"],"nguoiTu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1872","tangDatToi":"chủ trì nghi thức","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1872","loai":"xuất hiện","importance":"normal","giaiDoan":"Đại lễ sắc phong","text":"Thượng Huyền Đạo dùng huyết tế tiên để mở tiên đạo, dẫn sinh linh thiên ngoại tới trước Tiên Đạo Điện.","anchor":"Đại lễ sắc phong do ta chủ trì, kế tiếp lấy huyết tế tiên, mở ra tiên đạo!"}]},"capNhatToi":"@c1872","nguon":["@c1872"]},{"id":"dao-vo-cua-thuong-huyen-dao-quoc-su","name":"Đạo “Vô” của Thượng Huyền Đạo quốc sư","cn":"","loai":"than-thong","loaiLabel":"Đạo pháp","phamCap":"Không rõ","hePhai":"Tiên Tộc","soHuu":["Thượng Huyền Đạo"],"blurb":"Đạo pháp của Thượng Huyền Đạo quốc sư dựa trên minh ngộ về “vô”. Một chỉ của ông khiến hư ảnh Thiên Ngưu tan biến trong đại lễ sắc phong.","detail":"Thượng Huyền Đạo dùng một chỉ kèm lời giảng về “vô” để làm hư ảnh Thiên Ngưu tan thành mây khói. Màn thi triển khiến Vương Lâm cảm nhận dao động đạo pháp cực kỳ đáng sợ từ quốc sư.","thuocTinh":"Đạo pháp về “vô”","uyLuc":"Có thể khiến hư ảnh Thiên Ngưu đang lao tới tan biến.","dacDiem":"Gắn với minh ngộ sâu đối với đạo.","congNang":["Làm mục tiêu hoặc hư ảnh mất đi, tan biến khi bị đạo “vô” tác động @c1873"],"nguoiTu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1873","tangDatToi":"Không rõ","trangThai":"đang thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1873","loai":"thi triển","importance":"normal","giaiDoan":"Một chỉ trước Tiên Đạo Điện","text":"Thượng Huyền Đạo dùng một chỉ và lời giảng về “vô” khiến hư ảnh Thiên Ngưu tan biến.","anchor":"Bởi vì có nhân tồn tại, cho nên sau khi mất đi liền được gọi là vô"}]},"capNhatToi":"@c1873","nguon":["@c1873"]},{"id":"hac-khi-ngung-anh-hien-te","name":"Hắc khí ngưng ảnh hiến tế","cn":"","loai":"than-thong","loaiLabel":"Thần thông hiến tế","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["La Công"],"blurb":"Thần thông của La Công dùng hắc khí ngưng thành bóng đen giáp trụ. Uy lực có thể được thúc đẩy bằng máu tươi, thọ nguyên và sinh cơ.","detail":"La Công dùng hắc khí ngưng tụ bóng đen mặc giáp, sau đó phun máu kích phát. Khi bị Vương Lâm đánh tan lần đầu, ông tiếp tục hiến tế thọ nguyên và sinh cơ để tái tạo bóng đen cùng chiến mã, nhưng cuối cùng vẫn bị Thiên Ngưu Chàng phá hủy.","thuocTinh":"Hắc khí, hiến tế","yeuCau":"Có thể tiêu hao máu tươi, thọ nguyên và sinh cơ để tăng uy lực.","uyLuc":"Tạo bóng đen giáp trụ và chiến mã hắc khí lao vào đối thủ.","dacDiem":"Đại giá rõ rệt là tiêu hao thọ nguyên và sinh cơ của người thi triển.","congNang":["Ngưng hắc khí thành bóng đen giáp trụ để công kích @c1873","Hiến tế thọ nguyên và sinh cơ để tái ngưng bóng đen cùng chiến mã @c1873"],"nguoiTu":[{"ten":"La Công","tuChuong":"@c1873","tangDatToi":"Không rõ","trangThai":"đang thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1873","loai":"thi triển","importance":"normal","giaiDoan":"Khiêu chiến Vương Lâm","text":"La Công dùng hắc khí ngưng bóng đen giáp trụ rồi hiến tế thọ nguyên và sinh cơ để tái tạo bóng đen cùng chiến mã.","anchor":"Cái vỗ này hắn hiến tế thọ nguyên và sinh cơ"}]},"capNhatToi":"@c1873","nguon":["@c1873"]},{"id":"phong-an-giam-cam","name":"Phong ấn giam cầm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp/cấm chế","phamCap":"khong-ro","hePhai":"","soHuu":[],"blurb":"Cấm chế phong tỏa xuất hiện trên con phố tuyết khi Vương Lâm và Hải Tử Thiên Tôn tới truyền tống trận Đế Sơn.","detail":"Phong ấn giam cầm được Hải Tử Thiên Tôn nhận ra qua dao động trên đường tuyết, báo hiệu một bố trí nhằm khóa giữ hoặc vây hãm không gian quanh hai người.","dinhDanh":"goc","congNang":["Giam cầm hoặc phong tỏa mục tiêu trong phạm vi bố trí @c1875"],"trangThai":"đang xuất hiện","capNhatToi":"@c1875","tabs":{"tienTrinh":[{"chuong":"@c1875","loai":"xuất hiện","importance":"normal","giaiDoan":"Phục kích trong gió tuyết","text":"Phong ấn giam cầm dao động trên con phố tuyết khi Vương Lâm và Hải Tử Thiên Tôn đang đi tới truyền tống trận Đế Sơn.","anchor":"Có dao động của phong ấn giam cầm"}]},"nguon":["@c1875"]},{"id":"do-an-bon-canh-tuyet-sat-cuc","name":"Đồ án bốn cạnh tuyết sát cục","cn":"","loai":"khac","loaiLabel":"Trận pháp sát cục","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Đồ án do tuyết phía trước phố dài ngưng tụ thành, lao vào Vương Lâm trong sát cục. Sau khi bị đánh tan, nó vẫn để lực lượng Vô xâm nhập cơ thể hắn.","detail":"Đồ án bốn cạnh tăng vọt tới hơn trăm trượng rồi lao tới Vương Lâm. Bên trong ẩn chứa lực lượng Vô, sau khi đồ án bị phá thì lực lượng này chui vào cơ thể hắn, hóa thành lưới phong ấn ký sinh trong kinh mạch huyết nhục.","congNang":["Công kích trực diện bằng đồ án tuyết quy mô lớn @c1876","Ẩn lực lượng Vô để xâm nhập và phong ấn thân thể mục tiêu @c1876"],"uyLuc":"Bị một quyền cực hạn của Vương Lâm đánh tan nhưng vẫn hoàn thành hiệu quả phong ấn.","dacDiem":"Là lớp mở đầu của sát cục phố dài, phối hợp với đồ án ba cạnh để khóa hai hướng.","capNhatToi":"@c1876","tabs":{"tienTrinh":[{"chuong":"@c1876","loai":"xuất hiện","importance":"normal","giaiDoan":"Sát cục mở màn","text":"Đồ án bốn cạnh tuyết hình thành phía trước phố dài, lao vào Vương Lâm và để lại lực lượng Vô phong ấn sau khi bị phá.","anchor":"hình thành một đồ án bốn cạnh"}]},"nguon":["@c1876"]},{"id":"do-an-ba-canh-tuyet-sat-cuc","name":"Đồ án ba cạnh tuyết sát cục","cn":"","loai":"khac","loaiLabel":"Trận pháp sát cục","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Đồ án tuyết xuất hiện phía cuối phố sau lưng Vương Lâm và Hải Tử Thiên Tôn. Nó mang sát khí lao tới, buộc Hải Tử Thiên Tôn quay lại ứng phó.","detail":"Đồ án ba cạnh là phần khóa hậu phương trong sát cục phố dài. Nó cùng đồ án bốn cạnh ép hai người vào thế bị chia cắt trước sau, khiến Vương Lâm phải phân công mỗi người xử lý một hướng.","congNang":["Chia cắt hướng sau và ép Hải Tử Thiên Tôn phải quay lại ứng phó @c1876"],"dacDiem":"Phối hợp với đồ án bốn cạnh để tạo thế kẹp trước sau.","capNhatToi":"@c1876","tabs":{"tienTrinh":[{"chuong":"@c1876","loai":"xuất hiện","importance":"normal","giaiDoan":"Khóa hậu phương","text":"Đồ án ba cạnh tuyết hình thành phía sau, mang sát khí lao tới và chia cắt Hải Tử Thiên Tôn khỏi Vương Lâm.","anchor":"hình thành một đồ án ba cạnh"}]},"nguon":["@c1876"]},{"id":"mot-quyen-chin-muoi-hai-dao-than-thong-cua-vuong-lam","name":"Một quyền chín mươi hai đạo thần thông của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Một quyền cực hạn Vương Lâm dùng trong trạng thái Thiên Ngưu Hồn Khải. Quyền này dung hợp nhiều tầng thần thông để đánh tan đồ án bốn cạnh.","detail":"Vương Lâm dùng Hồn Khải phối hợp, qua ba lần dừng quyền để tăng số thần thông dung nhập, đạt cực hạn khi không dùng phân thân hư vô. Một quyền này đánh tan đồ án bốn cạnh trên phố dài.","congNang":["Dung hợp nhiều đạo thần thông vào một quyền để tăng uy lực @c1876","Đánh tan đồ án bốn cạnh tuyết sát cục @c1876"],"uyLuc":"Đạt cực hạn hiện tại của Vương Lâm khi không dùng phân thân hư vô.","capNhatToi":"@c1876","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1876","tangDatToi":"Cực hạn không dùng phân thân hư vô","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1876","loai":"thi triển","importance":"normal","giaiDoan":"Phá đồ án bốn cạnh","text":"Vương Lâm vận dụng một quyền dung hợp nhiều tầng thần thông tới cực hạn không dùng phân thân hư vô và đánh tan đồ án bốn cạnh.","anchor":"trực tiếp đạt tới cực hạn khi hắn không dùng phân thân trong hư vô"}]},"nguon":["@c1876"]},{"id":"luc-luong-vo-phong-an","name":"Lực lượng Vô phong ấn","cn":"","loai":"khac","loaiLabel":"Lực lượng phong ấn","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Lực lượng quỷ dị ẩn trong đồ án bốn cạnh, chui vào cơ thể Vương Lâm sau khi đồ án bị phá. Nó hóa thành lưới ký sinh trong kinh mạch huyết nhục để giam cầm thân thể hắn.","detail":"Lực lượng này được Vương Lâm nhận ra có hơi hướng Vô, loại hắn từng thấy trên người Thượng Huyền Đạo. Khi nhập thể, nó hình thành tấm lưới nhỏ trong cơ thể, khiến thân thể bị giam cầm, bước chân chậm lại và phong ấn càng tăng khi bị sáu Thiên Tôn hai bên điểm chỉ.","congNang":["Chui vào cơ thể mục tiêu sau khi đồ án bốn cạnh bị phá @c1876","Hóa thành lưới ký sinh trong kinh mạch huyết nhục để giam cầm thân thể @c1876","Có thể được kích phát tăng mạnh bởi công kích phối hợp từ bên ngoài @c1876"],"uyLuc":"Khiến Vương Lâm bị chậm lại đúng khoảnh khắc mười lăm Thiên Tôn vây sát.","dacDiem":"Có liên hệ với lực lượng Vô mà Vương Lâm từng thấy ở Thượng Huyền Đạo.","capNhatToi":"@c1876","tabs":{"tienTrinh":[{"chuong":"@c1876","loai":"xuất hiện","importance":"normal","giaiDoan":"Phong ấn nhập thể","text":"Lực lượng Vô chui vào cơ thể Vương Lâm sau khi đồ án bốn cạnh bị phá, hóa thành lưới ký sinh trong kinh mạch huyết nhục và giam cầm hắn.","anchor":"Tấm lưới này ký sinh trong kinh mạch huyết nhục của Vương Lâm"}]},"nguon":["@c1876"]},{"id":"huyet-don-thuat-cua-ba-thien-ton-phia-truoc","name":"Huyết độn thuật của ba Thiên Tôn phía trước","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật độn pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Mười hai Thiên Tôn còn lại trong vòng vây đầu"],"blurb":"Thuật pháp ba Thiên Tôn phía trước dùng để tăng tốc áp sát Vương Lâm. Họ phun máu rồi thi triển huyết độn, lao tới dưới nửa trượng.","detail":"Trong vòng vây đầu, ba Thiên Tôn phía trước cắn đầu lưỡi phun máu tươi, nhờ huyết độn thuật mà tốc độ tăng vọt. Thuật này giúp họ áp sát Vương Lâm trong lúc phong ấn trên người hắn đang tăng mạnh.","congNang":["Tăng tốc độ áp sát bằng cách phun máu thi triển @c1876"],"capNhatToi":"@c1876","tabs":{"tienTrinh":[{"chuong":"@c1876","loai":"thi triển","importance":"normal","giaiDoan":"Áp sát trước mặt","text":"Ba Thiên Tôn phía trước phun máu thi triển huyết độn thuật để tăng tốc áp sát Vương Lâm.","anchor":"phun ra một ngụm máu tươi, thi triển huyết độn thuật"}]},"nguon":["@c1876"]},{"id":"bang-long-hop-kich","name":"Băng long hợp kích","cn":"","loai":"than-thong","loaiLabel":"Thần thông hợp kích","phamCap":"Không rõ","hePhai":"","soHuu":["Chín thân ảnh tạo băng long phía trước phố"],"blurb":"Thần thông hợp kích do chín thân ảnh phía trước phố dài cùng thi triển. Nó tạo ra băng long dữ tợn lao vào Vương Lâm nhưng bị Thiên Ngưu hiển hóa phá nát.","detail":"Chín thân ảnh bắt quyết theo phương thức đặc biệt và dung hợp lực lượng, khiến bầu trời phía trên xuất hiện băng long. Băng long công kích Vương Lâm trong lớp phục kích tiếp theo, nhưng bị hư ảnh Thiên Ngưu húc vỡ, khiến chín người thi triển bị phản chấn.","congNang":["Chín người hợp lực tạo băng long công kích mục tiêu @c1876"],"uyLuc":"Tạo băng long dữ tợn trên bầu trời, nhưng không chống nổi Thiên Ngưu hiển hóa của Vương Lâm.","capNhatToi":"@c1876","tabs":{"tienTrinh":[{"chuong":"@c1876","loai":"thi triển","importance":"normal","giaiDoan":"Hợp kích phía trước","text":"Chín thân ảnh phía trước phố hợp lực tạo băng long dữ tợn công kích Vương Lâm, sau đó bị Thiên Ngưu hiển hóa phá nát.","anchor":"bầu trời phía trên họ xuất hiện một con băng long"}]},"nguon":["@c1876"]},{"id":"thien-nguu-hien-hoa","name":"Thiên Ngưu hiển hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông hư ảnh","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hư ảnh Thiên Ngưu khổng lồ hiển hóa bên ngoài thân thể Vương Lâm. Nó ngưng thật như sống lại và húc nát băng long hợp kích.","detail":"Khi đối mặt băng long và các tầng phục kích, Vương Lâm bộc phát sát khí, khiến bên ngoài thân thể xuất hiện hư ảnh Thiên Ngưu khổng lồ. Hư ảnh này gầm thét, lao vào băng long, làm nó tan rã và khiến chín người hợp kích phun máu bị cuốn bay.","congNang":["Hiển hóa hư ảnh Thiên Ngưu khổng lồ ngoài thân @c1876","Phá tan băng long hợp kích của chín người @c1876"],"uyLuc":"Húc nát băng long và phản chấn nhóm thi triển.","capNhatToi":"@c1876","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1876","tangDatToi":"Thi triển phá băng long","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1876","loai":"thi triển","importance":"normal","giaiDoan":"Phá băng long","text":"Vương Lâm hiển hóa Thiên Ngưu khổng lồ ngoài thân, húc thẳng vào băng long và phá tan nó.","anchor":"bên ngoài thân thể Vương Lâm bỗng có một hư ảnh Thiên Ngưu khổng lồ"}]},"nguon":["@c1876"]},{"id":"gio-tuyet-bao","name":"Gió tuyết bạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":["Ba thân ảnh áo trắng gần Dược Thiên Tôn"],"blurb":"Thần thông do ba áo trắng ngưng tụ sức mạnh gió tuyết để tạo vụ nổ và cuồng phong quét ngang thiên địa.","detail":"Ba thân ảnh áo trắng dùng sức mạnh gió tuyết tạo vụ nổ lớn nhằm đánh Vương Lâm trong đợt sát kích thứ hai. Đây là một trong hai thức họ sử dụng trước khi tự bạo.","congNang":["Ngưng tụ sức mạnh gió tuyết thành vụ nổ và cuồng phong công kích diện rộng @c1877"],"tabs":{"tienTrinh":[{"chuong":"@c1877","loai":"thi triển","importance":"normal","giaiDoan":"Đợt sát kích thứ hai","text":"Ba áo trắng ngưng tụ sức mạnh gió tuyết thành vụ nổ để công kích Vương Lâm.","anchor":"ngưng tụ sức mạnh của gió tuyết, hình thành một vụ nổ gió tuyết"}]},"nguon":["@c1877"]},{"id":"tu-bao-cua-ba-ao-trang","name":"Tự bạo của ba áo trắng","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật hi sinh","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":["Ba thân ảnh áo trắng gần Dược Thiên Tôn"],"blurb":"Chiến thuật hi sinh của ba áo trắng gần Dược Thiên Tôn, tạo sức nổ lớn để ép Vương Lâm phải dùng Dịch Linh Ấn chống đỡ.","detail":"Sau gió tuyết bạo, ba áo trắng tự bạo thân thể làm thức thứ hai. Sức nổ kinh thiên động địa khiến Vương Lâm phải triển khai chín mươi chín Dịch Linh Ấn để đối kháng.","congNang":["Tạo sức nổ từ thân thể để công kích và tiêu hao đối thủ @c1877"],"uyLuc":"Sức nổ được mô tả là kinh thiên động địa trong trận chiến với Vương Lâm.","tabs":{"tienTrinh":[{"chuong":"@c1877","loai":"thi triển","importance":"normal","giaiDoan":"Tự bạo trong phố tuyết","text":"Ba áo trắng tự bạo thân thể, buộc Vương Lâm dùng Dịch Linh Ấn đối kháng.","anchor":"đối mặt với ba người áo trắng tự bạo thân thể"}]},"nguon":["@c1877"]},{"id":"hac-phong-hoa-hac-xa","name":"Hắc phong hóa hắc xà","cn":"","loai":"than-thong","loaiLabel":"Thần thông hồn phong","phamCap":"chưa rõ","hePhai":"Hồn khải sứ giả","soHuu":["Hai Hồn khải sứ giả áo đen"],"blurb":"Thần thông của hai Hồn khải sứ giả áo đen, khiến hắc phong trong gió tuyết hóa thành hai con rắn đen lớn.","detail":"Hai áo đen giơ tay khiến hắc phong gào thét giữa gió tuyết, hóa thành hai con rắn đen chiếm cứ thiên địa trong trận đánh với Vương Lâm.","congNang":["Biến hắc phong thành hai rắn đen lớn để áp trận và công kích @c1877"],"tabs":{"tienTrinh":[{"chuong":"@c1877","loai":"thi triển","importance":"normal","giaiDoan":"Hai áo đen ra tay","text":"Hai Hồn khải sứ giả áo đen thi triển hắc phong hóa thành hai con rắn lớn màu đen.","anchor":"hắc phong gào thét, hóa thành hai con rắn lớn màu đen"}]},"nguon":["@c1877"]},{"id":"do-an-giam-cam-chien-luc","name":"Đồ án giam cầm chiến lực","cn":"","loai":"khac","loaiLabel":"Trận pháp giam cầm","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":["Chủ nhân ngón tay bí ẩn"],"blurb":"Đồ án được bố trí ở bốn phía chiến trường bởi chủ nhân ngón tay bí ẩn, có tác dụng phong bế khí tức và giam cầm chiến lực của Vương Lâm.","detail":"Trong trận chiến tại chương 1877, Vương Lâm nhận ra rằng chủ nhân ngón tay bí ẩn đã bố trí đồ án ở bốn phía chiến trường. Đồ án này giam cầm toàn bộ chiến trường, phong bế khí tức và hạn chế chiến lực của hắn. Tuy nhiên, về sau đồ án bị kim quang từ phân thân cùng trận mảnh cốt đao làm suy yếu rồi phá hủy bên trong cơ thể hắn.","congNang":["Phong bế khí tức chiến trường và hạn chế chiến lực của mục tiêu @c1877"],"trangThai":"bị phá trong cơ thể Vương Lâm","tabs":{"tienTrinh":[{"chuong":"@c1877","loai":"xuất hiện","importance":"major","giaiDoan":"Sát cục phố tuyết","text":"Đồ án giam cầm chiến lực bị Vương Lâm nhận ra là do chủ nhân ngón tay bố trí ở bốn phía chiến trường.","anchor":"Cũng chính là chủ nhân của ngón tay này đã bố trí đồ án ở bốn phía"}]},"nguon":["@c1877"],"dacDiem":"Bố trí ở bốn phía chiến trường, giam cầm toàn bộ không gian giao đấu"},{"id":"tran-phap-manh-cot-dao-phan-kim-quang","name":"Trận pháp mảnh cốt đao phản kim quang","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"chưa rõ","hePhai":"Cấm chế bổn nguyên của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Trận pháp nhỏ do Vương Lâm dùng các mảnh cốt âm đao vỡ làm nền, phản chiếu kim quang để phá giam cầm và đối chỉ với kẻ bí ẩn.","detail":"Sau khi cốt âm đao nứt vỡ, Vương Lâm dùng các mảnh cốt đao làm trận pháp, phản chiếu kim quang từ hai mắt để hình thành trận pháp nhỏ. Trận này phối hợp với phân thân cực mạnh trong hư vô, phá giam cầm và giúp hắn giơ tay đối một chỉ với ngón tay bí ẩn.","congNang":["Phản chiếu kim quang từ hai mắt để lập trận, phá giam cầm và đối kháng ngón tay bí ẩn @c1877"],"tabs":{"tienTrinh":[{"chuong":"@c1877","loai":"thi triển","importance":"normal","giaiDoan":"Đối chỉ cuối chương","text":"Vương Lâm dùng mảnh cốt đao làm trận pháp phản chiếu kim quang rồi đối kháng ngón tay bí ẩn.","anchor":"Lấy những mảnh của cốt đao làm trận pháp, phản chiếu kim quang từ trong hai mắt"}]},"nguon":["@c1877"]},{"id":"phan-than-cuc-manh-trong-hu-vo-cua-vuong-lam","name":"Phân thân cực mạnh trong hư vô của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Phân thân","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Phân thân được Vương Lâm cố ý ẩn trong hư vô từ đầu trận, chỉ lộ tác dụng khi chủ nhân ngón tay bí ẩn ra tay.","detail":"Vương Lâm không dùng phân thân ngay từ đầu mà giấu trong hư vô để chờ ngón tay bí ẩn xuất hiện. Khi bị giam cầm và tập kích, kim quang từ phân thân cực mạnh truyền qua hai mắt bản thể, làm suy yếu và phá hủy giam cầm trong cơ thể hắn.","congNang":["Phóng kim quang qua bản thể để phá giam cầm chiến lực @c1877"],"tabs":{"tienTrinh":[{"chuong":"@c1877","loai":"xuất hiện","importance":"normal","giaiDoan":"Phá giam cầm","text":"Phân thân cực mạnh trong hư vô của Vương Lâm phát kim quang qua hai mắt bản thể để phá giam cầm.","anchor":"Kim quang này đến từ phân thân cực mạnh của Vương Lâm ở trong hư vô"}]},"nguon":["@c1877"]},{"id":"sat-luc-loi-dinh-bon-nguyen","name":"Sát lục lôi đình bổn nguyên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Bổn nguyên / thần thông căn cơ","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Sát lục lôi đình bổn nguyên làổn nguyên sát lục lôi đình tồn tại trong cơ thể Vương Lâm. Tại sát cục phố tuyết, khi đối diện liên hoàn sát cục, nó lần đầu trở thành chủ đạo trong cơ thể hắn, đánh dấu trạng thái chiến đấu nghiêng hẳn về sát lục.","detail":"Sát lục lôi đình bổn nguyên vốn bị cấm chế bên trong cơ thể Vương Lâm. Khi đối mặt sát cục liên tục của ngón tay thần bí, tử sĩ và trăm thân ảnh Thiên Tôn tại phố tuyết, Vương Lâm quyết định không rời đi mà buông lỏng cấm chế, để sát lục lôi đình bổn nguyên lần đầu trở thành chủ đạo. Điều này báo hiệu trạng thái chiến đấu hoàn toàn nghiêng về sát lục, thúc đẩy sát lục lôi đình bộc phát.","thuocTinh":"Sát lục lôi đình","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1878","tangDatToi":"Lần đầu để bổn nguyên làm chủ đạo","trangThai":"đang tu"}],"congNang":["Khi được buông lỏng cấm chế, trở thành chủ đạo trong cơ thể Vương Lâm và thúc đẩy sát lục lôi đình bộc phát @c1878"],"tabs":{"tienTrinh":[{"chuong":"@c1878","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lần đầu chủ đạo","text":"Vương Lâm lần đầu để sát lục lôi đình bổn nguyên trở thành chủ đạo trong cơ thể khi quyết định không rời sát cục.","anchor":"Sát lục lôi đình bổn nguyên trong cơ thể hắn lần đầu tiên trở thành chủ đạo"}]},"capNhatToi":"@c1878","nguon":["@c1878"],"dacDiem":"Bình thường bị cấm chế, chỉ trở thành chủ đạo khi Vương Lâm chủ động buông lỏng trong trạng thái sát cục."},{"id":"thai-so-bon-nguyen","name":"Thái Sơ bổn nguyên","cn":"","aliases":["Tàn Dạ lực"],"loai":"than-thong","loaiLabel":"Bổn nguyên","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thái Sơ bổn nguyên là bổn nguyên liên hệ với lực Tàn Dạ của Vương Lâm. Trong sát cục phố tuyết, nó được buông lỏng cùng cấm chế sát lục lôi đình chân thân để khiến sát lục lôi đình bộc phát.","detail":"Khi Vương Lâm lựa chọn ở lại giết sạch kẻ trong sát cục, hắn buông lỏng cấm chế cho Thái Sơ bổn nguyên. Việc này đi cùng mốc sát lục lôi đình bổn nguyên trở thành chủ đạo, làm sức sát lục trong lôi đình bùng phát.","thuocTinh":"Thái Sơ","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1878","tangDatToi":"Được buông lỏng cấm chế trong sát cục","trangThai":"đang tu"}],"congNang":["Được buông lỏng cùng cấm chế sát lục lôi đình chân thân để khiến sát lục lôi đình bộc phát @c1878"],"tabs":{"tienTrinh":[{"chuong":"@c1878","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Buông lỏng cấm chế","text":"Vương Lâm buông lỏng Thái Sơ bổn nguyên cùng cấm chế sát lục lôi đình chân thân để thúc đẩy sát lục lôi đình bộc phát.","anchor":"buông lỏng cho Thái Sơ bổn nguyên, khiến cho sát lục lôi đình trong lôi đình bộc phát ra"}]},"capNhatToi":"@c1878","nguon":["@c1878"]},{"id":"tam-dai-hu-bon-nguyen","name":"Tam đại hư bổn nguyên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Bổn nguyên","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ba hư bổn nguyên thuộc cảm ngộ căn bản cả đời của Vương Lâm. Trong lần va chạm với đạo Hữu/Không, chúng vẫn tồn tại khi nhiều lực lượng khác bị hóa thành hư vô.","detail":"Khi ngón tay thần bí dùng đạo Không hóa giải lực lượng Đạo cổ, thần mạch, Hồn Khải, ngũ hành chân thân và lôi đình chân thân trên một chỉ của Vương Lâm, tam đại hư bổn nguyên vẫn không bị xua tan. Điều này cho thấy chúng là phần căn cơ cảm ngộ bền vững của hắn trong cuộc đối kháng đạo pháp.","thuocTinh":"Hư bổn nguyên","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1878","tangDatToi":"Vẫn tồn tại trước đạo Không","trangThai":"đang tu"}],"congNang":["Không bị đạo Không của ngón tay thần bí xua tan trong lần va chạm tại phố tuyết."],"tabs":{"tienTrinh":[{"chuong":"@c1878","loai":"thi triển","importance":"normal","giaiDoan":"Chống đạo Không","text":"Tam đại hư bổn nguyên của Vương Lâm vẫn tồn tại sau khi nhiều tầng lực lượng khác trên một chỉ bị hóa thành hư vô.","anchor":"Nhưng tam đại hư bổn nguyên của hắn lại vẫn tồn tại như trước"}]},"capNhatToi":"@c1878","nguon":["@c1878"]},{"id":"dao-huu-khong-cua-ngon-tay-than-bi","name":"Đạo Hữu/Không của ngón tay thần bí","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đạo pháp","phamCap":"Không rõ","hePhai":"Tông môn của người phát ra giọng nói bình tĩnh","soHuu":["Chủ nhân ngón tay bí ẩn"],"blurb":"Đạo pháp thần bí do giọng nói bình tĩnh thi triển trong sát cục phố tuyết. Nó khiến ngón tay tan rồi tái ngưng tụ và hóa giải nhiều tầng lực lượng của Vương Lâm.","detail":"Đạo Hữu/Không được biểu hiện qua lời nói của chủ nhân ngón tay thần bí. Khi nói về Hữu, ngón tay đã bị đánh tan lại ngưng tụ; khi nói về Không, nhiều lực lượng đang tồn tại trên một chỉ của Vương Lâm bị hóa thành hư vô.","thuocTinh":"Hữu và Không","congNang":["Tái ngưng tụ ngón tay đã tan nát.","Hóa giải nhiều tầng lực lượng đang tồn tại trên công kích của Vương Lâm."],"tabs":{"tienTrinh":[{"chuong":"@c1878","loai":"thi triển","importance":"normal","giaiDoan":"Hóa giải một chỉ","text":"Chủ nhân ngón tay thần bí dùng đạo Hữu/Không để tái ngưng tụ ngón tay và làm nhiều lực lượng trên một chỉ của Vương Lâm hóa thành hư vô.","anchor":"Nhân tồn tại cho nên sau khi biến mất mới gọi là Không"}]},"capNhatToi":"@c1878","nguon":["@c1878"]},{"id":"tran-phap-mat-cot-am-dao","name":"Trận pháp mặt cốt âm đao","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Trận pháp hình thành trên mặt mảnh cốt âm đao trong tay Vương Lâm. Nó phóng đại lực lượng phân thân trong hư vô thông qua kim quang phản chiếu.","detail":"Trong sát cục phố tuyết, mảnh vỡ cốt âm đao phản chiếu kim quang trong mắt Vương Lâm và hình thành trận pháp trên mặt đao nhỏ. Trận pháp này phóng đại lực phân thân trong hư vô, rồi theo mảnh đao vỡ tan bắn tới ngón tay đang tái ngưng tụ.","thuocTinh":"Kim quang và lực phân thân hư vô","congNang":["Phóng đại lực lượng phân thân trong hư vô thông qua kim quang trên mảnh cốt âm đao."],"tabs":{"tienTrinh":[{"chuong":"@c1878","loai":"thi triển","importance":"normal","giaiDoan":"Phóng lực phân thân","text":"Trận pháp trên mặt mảnh cốt âm đao phóng đại lực phân thân trong hư vô khi Vương Lâm đánh ngón tay đang tái ngưng tụ.","anchor":"trận pháp được hình thành tại mặt đao không lớn này phóng ra"}]},"capNhatToi":"@c1878","nguon":["@c1878"]},{"id":"sat-luc-loi-dinh-mau-den","name":"Sát lục lôi đình màu đen","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lôi đình màu đen phát ra từ trạng thái tóc đen của Vương Lâm. Nó mang sức chết chóc hủy diệt, có thể tàn sát diện rộng và phá sức tự bạo của tử sĩ.","detail":"Trong trận phục kích trên đường tuyết, Vương Lâm dùng lôi đình đen tạo thành tấm lưới lan ra bốn phía. Phàm kẻ bị lôi đình chạm phải đều run lên rồi thân hình tan nát, khiến lớp tử sĩ không sợ chết cũng chấn động.","congNang":["Tạo lưới lôi đình màu đen để nghiền nát nhiều mục tiêu cùng lúc @c1879","Đối kháng và phá sức tự bạo của tử sĩ @c1879"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1879","tangDatToi":"Thi triển trong trạng thái tóc đen","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1879","loai":"thi triển","importance":"normal","giaiDoan":"Tàn sát lớp tử sĩ đầu tiên","text":"Vương Lâm phát ra vô số lôi đình màu đen, hóa thành lưới nghiền nát các tử sĩ lao tới và phá sức tự bạo của họ.","anchor":"Chỉ thấy vô số lôi đình màu đen bỗng nhiên xuất hiện, vờn quanh bốn phía Vương Lâm"}]},"trangThai":"đang thi triển","capNhatToi":"@c1879","nguon":["@c1879"]},{"id":"tran-phap-dia-khi-cua-tu-si","name":"Trận pháp địa khí của tử sĩ","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Đám tử sĩ phục kích","soHuu":["Mấy trăm tử sĩ / mấy vạn thân ảnh mơ hồ"],"blurb":"Trận pháp quỷ dị do trăm tử sĩ hợp lực ngưng tụ. Nó dẫn địa khí hóa thành bàn tay đen khổng lồ để chụp xuống Vương Lâm.","detail":"Khi các tử sĩ kết trận, mặt đất chấn động và địa khí dung nhập vào trận pháp, khiến một cánh tay lớn màu đen hình thành. Vương Lâm dùng hàng trăm đạo lôi đình đen lao thẳng vào, phá nát cánh tay và toàn bộ người trong trận.","congNang":["Dẫn địa khí từ mặt đất, hóa thành bàn tay đen khổng lồ chụp mục tiêu @c1879"],"nguoiTu":[{"ten":"Mấy trăm tử sĩ / mấy vạn thân ảnh mơ hồ","tuChuong":"@c1879","tangDatToi":"Kết trận tập thể","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1879","loai":"thi triển","importance":"normal","giaiDoan":"Bàn tay địa khí bị phá","text":"Trăm tử sĩ dẫn địa khí hóa thành bàn tay đen chụp Vương Lâm, nhưng bị lôi đình đen phá nát cả trận lẫn người trong trận.","anchor":"mặt đất chấn động, dường như có địa khí phun lên, dũng mãnh dung nhập vào trong trận pháp"}]},"trangThai":"bị phá","capNhatToi":"@c1879","nguon":["@c1879"]},{"id":"ngon-tay-hoa-vo","name":"Ngón tay hóa Vô","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Thân ảnh ánh sáng màu trắng trong hư vô"],"blurb":"Thần thông một chỉ xuất hiện từ hư vô, kèm ý niệm khiến mọi thứ trở thành Vô. Nó được dùng để công kích mi tâm Vương Lâm nhưng bị trạng thái hủy diệt của hắn đánh tan.","detail":"Thân ảnh trong hư vô dùng ngón tay điểm thẳng tới Vương Lâm và phát ra lời tuyên bố mọi thứ đều sẽ trở thành Vô. Vương Lâm phản bác rằng hủy diệt cũng là hư vô rồi đánh quyền khiến ngón tay tiêu tán.","congNang":["Một chỉ từ hư vô nhằm làm mục tiêu tiêu tán thành Vô @c1879"],"nguoiTu":[{"ten":"Thân ảnh ánh sáng màu trắng trong hư vô","tuChuong":"@c1879","tangDatToi":"Thi triển từ hư vô","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1879","loai":"thi triển","importance":"normal","giaiDoan":"Một chỉ bị đánh tan","text":"Thân ảnh trong hư vô dùng ngón tay hóa Vô công kích Vương Lâm, nhưng bị Vương Lâm đánh tan bằng trạng thái hủy diệt tóc đen.","anchor":"Tất cả mọi thứ đều sẽ trở thành Vô"}]},"trangThai":"bị phá","capNhatToi":"@c1879","nguon":["@c1879"]},{"id":"sinh-tu-bon-nguyen-nhan-qua-bon-nguyen-chan-gia-bon-nguyen","name":"Sinh tử bổn nguyên / Nhân quả bổn nguyên / Chân giả bổn nguyên","cn":"","aliases":["Sinh tử bổn nguyên","Nhân quả bổn nguyên","Chân giả bổn nguyên"],"loai":"cong-phap","loaiLabel":"Hư bổn nguyên","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ba hư bổn nguyên bị Vương Lâm cưỡng ép rời khỏi thân trong quá trình tinh thuần hóa trạng thái tóc đen. Sau khi chúng bị bức ra, bản thể chỉ còn Mặc Diệt và sát lục.","detail":"Trước sức ép của mấy vạn thân ảnh, Vương Lâm lần lượt ép các lực lượng không thuộc trạng thái hủy diệt rời khỏi thân thể. Sinh tử, nhân quả và chân giả bị gọi ra cùng lúc, đánh dấu việc bản thể tóc đen tiến tới hình thái chỉ còn hai bổn nguyên cuối cùng.","congNang":["Ba hư bổn nguyên rời khỏi bản thể để Vương Lâm giữ lại trạng thái hủy diệt tinh thuần @c1879"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1879","tangDatToi":"Bị tách khỏi bản thể trong trạng thái tóc đen","trangThai":"tach-roi-tam-thoi"}],"tabs":{"tienTrinh":[{"chuong":"@c1879","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Ba hư bổn nguyên rời thân","text":"Vương Lâm gào thét bức sinh tử, nhân quả và chân giả rời khỏi cơ thể, khiến bản thể tóc đen tiến gần trạng thái chỉ còn Mặc Diệt và sát lục.","anchor":"Sinh tử. nhân quả. chân giả, đi ra cho ta"}]},"trangThai":"tách khỏi bản thể Vương Lâm trong trạng thái tóc đen","capNhatToi":"@c1879","nguon":["@c1879"]},{"id":"mac-diet-bon-nguyen","name":"Mặc Diệt bổn nguyên","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Bổn nguyên","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Mặc Diệt bổn nguyên là một trong hai bổn nguyên cuối cùng còn tồn tại trong bản thể tóc đen của Vương Lâm, gắn liền với hình thái tử vong hủy diệt cực đoan sau khi mọi chân thân và bổn nguyên khác đã bị bức ra ngoài.","detail":"Sau khi Thiên Ngưu Hồn Khải, Ngũ hành chân thân, cấm chế, thái sơ, lôi đình cùng ba hư bổn nguyên lần lượt rời khỏi thân thể, bản thể Vương Lâm tóc đen chỉ còn giữ lại Mặc Diệt và sát lục. Trạng thái này khiến hắc khí ngưng tụ co lại thành trường bào đen, và uy áp tử vong hủy diệt phát ra từ ánh mắt hắn đủ sức diệt sạch mấy vạn thân ảnh. Mặc Diệt bổn nguyên đại diện cho bản chất hủy diệt tối thuần của Vương Lâm khi mọi yếu tố khác đã bị tách bỏ.","congNang":["Là một trong hai bổn nguyên cuối cùng còn trong bản thể tóc đen của Vương Lâm, duy trì sự tồn tại của hình thái hủy diệt thuần túy @c1879","Gắn với trạng thái hắc khí hóa trường bào đen và uy áp tử vong hủy diệt, đủ sức diệt sạch mấy vạn thân ảnh @c1879"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1879","tangDatToi":"Còn lại trong bản thể tóc đen","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1879","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Hai bổn nguyên cuối","text":"Chương xác nhận bản thể Vương Lâm tóc đen chỉ còn Mặc Diệt và sát lục sau khi các lực lượng khác bị bức khỏi thân.","anchor":"chỉ còn hai đạo bổn nguyên, một là Mặc Diệt, một là sát lục"}]},"trangThai":"đang thuộc Vương Lâm","capNhatToi":"@c1879","nguon":["@c1879"],"uyLuc":"Uy áp tử vong hủy diệt phát ra từ ánh mắt Vương Lâm trong trạng thái chỉ còn Mặc Diệt và sát lục, diệt sạch mấy vạn thân ảnh.","dacDiem":"Biểu hiện dưới dạng hắc khí ngưng tụ thành trường bào đen, thể hiện bản chất hủy diệt tối thuần khi mọi lực lượng khác đã tách rời bản thể."},{"id":"sat-luc-va-huy-diet-tren-vuong-lam-toc-den","name":"Sát lục và hủy diệt trên Vương Lâm tóc đen","cn":"","loai":"than-thong","loaiLabel":"Lực lượng / trạng thái thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lực lượng sát lục và hủy diệt hiển lộ rõ trong trạng thái tóc đen của Vương Lâm, đủ để hắn giao thủ với Đại Thiên Tôn.","detail":"Cửu Đế nhận ra trên người Vương Lâm tóc đen tồn tại lực lượng đại biểu sát lục và hủy diệt. Lực lượng này gắn với trạng thái Lục Mặc, giúp hắn đối kháng Cửu Đế nhưng cũng khiến mặt sát phạt chiếm chủ thể khi đêm tối hoặc giết chóc phủ xuống.","thuocTinh":"Sát lục, hủy diệt","uyLuc":"Có thể chống lại Đại Thiên Tôn trong giao thủ trực diện.","dacDiem":"Gắn với trạng thái tóc đen Lục Mặc của Vương Lâm.","congNang":["Đối kháng Đại Thiên Tôn trong lúc giao thủ @c1880","Chiếm cứ chủ thể khi đêm tối hoặc sát lục phủ xuống @c1880"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1880","tangDatToi":"Hiển lộ trong trạng thái tóc đen","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1880","loai":"xuất hiện","importance":"normal","giaiDoan":"Hiển lộ trên Vương Lâm tóc đen","text":"Cửu Đế nhận ra lực lượng sát lục và hủy diệt trên người Vương Lâm tóc đen trong lúc giao thủ.","anchor":"Hóa ra trên người ngươi lại tồn tại lực lượng đại biểu sát lục và hủy diệt"}]},"capNhatToi":"@c1880","nguon":["@c1880"]},{"id":"tuyet-kiem-cua-cuu-de","name":"Tuyết kiếm của Cửu Đế","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cửu Đế Đại Thiên Tôn","soHuu":["Cửu Đế Đại Thiên Tôn"],"blurb":"Thần thông của Cửu Đế ngưng tụ gió tuyết đầy trời thành một thanh kiếm khổng lồ để chém Vương Lâm tóc đen.","detail":"Trong giao thủ với Vương Lâm tóc đen, Cửu Đế vận chuyển gió tuyết trong thiên địa, khiến chúng ngưng thành một tuyệt kiếm khổng lồ. Thanh kiếm bị một quyền của Vương Lâm tóc đen đánh nát.","thuocTinh":"Gió tuyết","uyLuc":"Ngưng gió tuyết thiên địa thành kiếm khổng lồ.","congNang":["Ngưng tụ gió tuyết đầy trời thành kiếm công kích @c1880"],"nguoiTu":[{"ten":"Cửu Đế Đại Thiên Tôn","tuChuong":"@c1880","tangDatToi":"Thi triển trong giao thủ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1880","loai":"thi triển","importance":"normal","giaiDoan":"Giao thủ với Vương Lâm tóc đen","text":"Cửu Đế ngưng tụ gió tuyết đầy trời thành một tuyệt kiếm khổng lồ để chém Vương Lâm tóc đen.","anchor":"gió tuyết đầy trời trong nháy mắt ngưng tụ lại, hóa thành một tuyệt kiếm khổng lồ"}]},"capNhatToi":"@c1880","nguon":["@c1880"]},{"id":"an-ky-anh-sang-cua-cuu-de","name":"Ấn ký ánh sáng của Cửu Đế","cn":"","loai":"than-thong","loaiLabel":"Thần thông / ấn pháp","phamCap":"Không rõ","hePhai":"Cửu Đế Đại Thiên Tôn","soHuu":["Cửu Đế Đại Thiên Tôn"],"blurb":"Ấn pháp của Cửu Đế phát ra ánh sáng bao phủ bốn phía để đối kháng hắc khí của Vương Lâm tóc đen.","detail":"Khi Vương Lâm tóc đen hóa thành hắc khí áp tới, Cửu Đế kết ấn tròn và phát ra ánh sáng từ trong ấn ký. Ánh sáng ấy lan ra đối kháng bóng tối sát lục của đối phương.","thuocTinh":"Ánh sáng","uyLuc":"Dùng ánh sáng từ ấn ký để chống lại hắc khí sát lục.","congNang":["Phát ánh sáng bao phủ bốn phía và đối kháng hắc khí sát lục @c1880"],"nguoiTu":[{"ten":"Cửu Đế Đại Thiên Tôn","tuChuong":"@c1880","tangDatToi":"Thi triển trong giao thủ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1880","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng hắc khí","text":"Cửu Đế kết ấn để ánh sáng từ trong ấn ký lan ra, đối kháng hắc khí của Vương Lâm tóc đen.","anchor":"Ánh sáng này từ trong ấn ký trong tay hắn lan ra"}]},"capNhatToi":"@c1880","nguon":["@c1880"]},{"id":"phong-an-ky-uc-tren-nguoi-dao-phi","name":"Phong ấn ký ức trên người Đạo Phi","cn":"","loai":"than-thong","loaiLabel":"Thần thông / cấm chế","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Tiên Hoàng"],"blurb":"Cấm chế hoặc thần thông che lấp ký ức của Đạo Phi, khiến ký ức về động phủ giới và Vương Lâm bị đứt đoạn.","detail":"Chương 1881 cho thấy ký ức của Đạo Phi từng bị phong ấn hoặc tác động bởi ca ca. Khi ký ức nới lỏng, hắn nhớ lại động phủ giới, Vương Lâm và dấu chưởng ấn trên cánh tay; sau đó Tiên Hoàng đặt tay khiến hắn mê man và dấu chưởng ấn biến mất.","thuocTinh":"Phong ấn ký ức","congNang":["Che lấp ký ức của Đạo Phi về động phủ giới, Vương Lâm và các sự kiện trước đó @c1881"],"uyLuc":"Khi phong ấn nới lỏng, Đạo Phi mới có thể nhớ lại các mảnh ký ức bị che khuất; Tiên Hoàng có thể cắt ngang quá trình này bằng một lần đặt tay.","dacDiem":"Liên hệ với trạng thái mê man của Đạo Phi và dấu chưởng ấn trên cánh tay hắn.","trangThai":"đang hiệu lực","capNhatToi":"@c1881","tabs":{"tienTrinh":[{"chuong":"@c1881","loai":"xuất hiện","importance":"normal","giaiDoan":"Ký ức Đạo Phi nới lỏng","text":"Phong ấn trong đầu Đạo Phi có dấu hiệu nới lỏng, khiến hắn nhớ lại động phủ giới và nghi vấn ca ca từng thi triển thần thông với mình.","anchor":"phong ấn trong đầu như có dấu hiệu nới lỏng"}]},"nguon":["@c1881"]},{"id":"tran-phap-mau-tim-tu-ngoc-gian-uoc-dinh","name":"Trận pháp màu tím từ ngọc giản ước định","cn":"","aliases":[],"loai":"khac","loaiLabel":"trận pháp truyền tống","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Trận pháp màu tím hiện ra khi Vương Lâm bóp vỡ ngọc giản ước định. Nó có vẻ tang thương, giống cơ chế truyền tống để gọi Song Tử Đại Thiên Tôn hiện thân.","detail":"Khi ngọc giản bị bóp nát, ánh sáng tím hóa thành một trận pháp kỳ dị, phức tạp trước mặt Vương Lâm. Trận pháp này đóng vai trò kích hoạt ước định và đưa Song Tử Đại Thiên Tôn tới nơi Vương Lâm đang đứng.","thuocTinh":"trận pháp màu tím","uyLuc":"Có thể gọi Song Tử Đại Thiên Tôn hiện thân theo ước định.","dacDiem":"Hiện ra từ ánh sáng tím sau khi ngọc giản bị bóp vỡ.","congNang":["Triệu gọi hoặc truyền tống Song Tử Đại Thiên Tôn tới chỗ Vương Lâm."],"trangThai":"đã kích hoạt","capNhatToi":"@c1882","tabs":{"tienTrinh":[{"chuong":"@c1882","loai":"xuất hiện","importance":"normal","giaiDoan":"kích hoạt ước định","text":"Trận pháp màu tím hiện ra từ ngọc giản bị bóp vỡ và gọi Song Tử Đại Thiên Tôn tới trước mặt Vương Lâm.","anchor":"hóa thành một trận pháp kỳ dị trước mặt Vương Lâm"}]},"nguon":["@c1882"]},{"id":"sat-luc-huy-diet-hoa-hac-am","name":"Sát lục hủy diệt hóa hắc ám","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"thần thông trạng thái","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Sát lục hủy diệt hóa hắc ám là trạng thái Vương Lâm chủ động buông thả sát lục và hủy diệt. Nó khiến tóc hắn hóa đen, tuyết hóa đen và bóng tối ăn mòn đường tiến vào hoàng cung.","detail":"Trong trạng thái này, Vương Lâm để sát lục và hủy diệt phủ lên thân mình, hắc khí bao quanh, tuyết trắng hóa thành tuyết đen. Khi hắn tiến về hoàng cung, mặt đất, kiến trúc và sinh cơ ven đường bị ăn mòn, suy tàn thành tro bụi.","thuocTinh":"sát lục, hủy diệt, hắc ám","uyLuc":"Có thể biến tuyết thành đen, phủ bóng tối lên một vùng tổ thành và ăn mòn cả kiến trúc lẫn sinh cơ.","dacDiem":"Gắn với biến hóa tóc trắng thành tóc đen của Vương Lâm.","congNang":["Hắc hóa tuyết trắng thành tuyết đen.","Ăn mòn thành quách, mặt đất và sinh linh trên đường Vương Lâm đi qua.","Áp đảo Long Quỷ do mấy vạn hắc giáp cấm binh ngưng tụ."],"trangThai":"đang được Vương Lâm thi triển","capNhatToi":"@c1882","tabs":{"tienTrinh":[{"chuong":"@c1882","loai":"thi triển","importance":"normal","giaiDoan":"tiến vào hoàng cung","text":"Vương Lâm chủ động trầm luân trong hủy diệt, dùng thần thông biến tuyết thành đen và để hắc ám ăn mòn đường tới hoàng cung.","anchor":"hắn lấy thần thông biến tuyết thành đen như mực"}]},"nguon":["@c1882"]},{"id":"long-quy-sat-khi-hop-nhat","name":"Long Quỷ sát khí hợp nhất","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"quân trận sát khí","phamCap":"không rõ","hePhai":"Hắc giáp cấm binh hoàng cung","soHuu":["Mấy vạn hắc giáp cấm binh"],"blurb":"Long Quỷ sát khí hợp nhất là quân trận do mấy vạn hắc giáp cấm binh cùng ngưng sát khí tạo thành. Nó hóa thành Long Quỷ khổng lồ để chặn Vương Lâm nhưng bị hủy diệt áp đảo.","detail":"Mấy vạn cấm binh hợp lực ngưng sát khí vô tận thành một Long Quỷ có hình rồng và dấu ấn mặt quỷ. Quân trận này lao vào mây đen của Vương Lâm nhưng nhanh chóng run rẩy, gào thét rồi sụp đổ.","thuocTinh":"sát khí hợp nhất","uyLuc":"Có thể hợp sát khí mấy vạn người thành hồn thú công kích.","dacDiem":"Phụ thuộc vào hắc giáp và sát khí của đội cấm binh.","congNang":["Hợp sát khí của mấy vạn hắc giáp cấm binh thành Long Quỷ khổng lồ để công kích."],"trangThai":"đã bị phá","capNhatToi":"@c1882","tabs":{"tienTrinh":[{"chuong":"@c1882","loai":"thi triển","importance":"normal","giaiDoan":"chặn Vương Lâm","text":"Mấy vạn hắc giáp cấm binh hợp sát khí thành Long Quỷ công kích Vương Lâm nhưng bị mây đen sát lục hủy diệt làm sụp đổ.","anchor":"Luồng sát khí này do mấy vạn người ngưng tụ ra"}]},"nguon":["@c1882"]},{"id":"hac-tuyet-cua-vuong-lam","name":"Hắc tuyết của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông khiến màn hắc ám hóa thành tuyết đen rơi khắp hoàng cung. Hắc tuyết làm kiến trúc hoàng cung xuống cấp nhanh chóng.","detail":"Vương Lâm thi triển hắc tuyết trước hoàng cung tiên tộc, biến màn hắc ám phủ càn khôn thành tuyết đen rơi trong ngoài hoàng cung. Tác dụng được thể hiện là ăn mòn hoặc khiến hoàng cung nhanh chóng xuống cấp, buộc kim quang trận pháp mạnh nhất của hoàng cung phải kích hoạt bảo hộ.","congNang":["Làm hoàng cung xuống cấp nhanh chóng @c1883"],"uyLuc":"Buộc trận pháp mạnh nhất của hoàng cung phải phát kim quang ngăn phá hủy.","dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1883","loai":"thi triển","importance":"normal","giaiDoan":"Giáng xuống hoàng cung","text":"Vương Lâm biến màn hắc ám thành tuyết đen rơi trong ngoài hoàng cung, khiến kiến trúc xuống cấp nhanh chóng.","anchor":"bất ngờ hóa thành những bông tuyết màu đen rơi xuống trong ngoài hoàng cung"}]},"capNhatToi":"@c1883","nguon":["@c1883"]},{"id":"tran-phap-manh-nhat-cua-hoang-cung","name":"Trận pháp mạnh nhất của hoàng cung","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Hoàng cung Tiên Tộc","soHuu":["Hoàng cung Tiên Tộc"],"blurb":"Trận pháp bảo hộ mạnh nhất của hoàng cung, biểu hiện bằng kim quang từ pho tượng Tiên Tổ. Nó ngăn hoàng cung bị hắc tuyết phá hủy.","detail":"Khi hắc tuyết của Vương Lâm khiến hoàng cung xuống cấp, pho tượng Tiên Tổ phát ra kim quang lan như gợn sóng, bao phủ hoàng cung và ngăn nơi này bị phá hủy. Research xác định đây là trận pháp mạnh nhất của hoàng cung.","congNang":["Bảo hộ hoàng cung, không cho phép nơi này bị phá hủy @c1883"],"uyLuc":"Có thể chống lại sự phá hoại lan rộng của hắc tuyết trong hoàng cung.","dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1883","loai":"xuất hiện","importance":"normal","giaiDoan":"Kim quang hộ cung","text":"Trận pháp mạnh nhất của hoàng cung được kích hoạt qua kim quang từ pho tượng Tiên Tổ để ngăn hủy diệt.","anchor":"Kim quang này chính là trận pháp mạnh nhất của hoàng cung, không cho phép bị phá hủy!"}]},"capNhatToi":"@c1883","nguon":["@c1883"]},{"id":"thuat-thanh-vo-cua-quoc-su","name":"Thuật thành Vô của quốc sư","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Tộc của quốc sư","soHuu":["Thượng Huyền Đạo"],"blurb":"Thần thông của quốc sư áo trắng khiến tồn tại trở thành Vô. Trong chương này, nó xóa các vết nứt do một cước của Vương Lâm tạo ra.","detail":"Quốc sư vung tay trước các khe nứt lan tới như địa long, nói hết thảy tồn tại đều có thể thành Vô. Những khe nứt khép lại rồi biến mất như chưa từng tồn tại.","congNang":["Xóa tồn tại của vết nứt, khiến chúng khép lại và biến mất @c1883"],"uyLuc":"Có thể hóa giải trực tiếp một cước phá địa của Vương Lâm trong hoàng cung.","dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1883","loai":"thi triển","importance":"normal","giaiDoan":"Xóa vết nứt","text":"Quốc sư dùng thuật thành Vô làm các vết nứt trên mặt đất khép lại và biến mất.","anchor":"Hết thảy tồn tại cũng đều thành có thể thành Vô"}]},"capNhatToi":"@c1883","nguon":["@c1883"]},{"id":"than-thong-mo-dong-phu-gioi-cua-toc-quoc-su","name":"Thần thông mở động phủ giới của tộc quốc sư","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Tộc của quốc sư","soHuu":["Tộc của quốc sư"],"blurb":"Thần thông độc hữu của tộc quốc sư, cho phép mở ra động phủ giới và sáng tạo một thế giới. Sau khi tộc này đi theo Tiên Tổ, thuật được truyền ra ngoài cho các tông môn đủ tư cách trên Tiên Cương Đại Lục.","detail":"Quốc sư tiết lộ thần thông mở động phủ giới và sáng tạo một thế giới trên thực tế chỉ tộc hắn có. Sau khi đi theo Tiên Tổ, tộc này truyền thuật ra ngoài để nhiều tông môn đủ tư cách trên Tiên Cương Đại Lục có thể tạo động phủ giới, qua đó vô số động phủ giới cung cấp hương hỏa cho tộc quốc sư.","nguonGoc":"Tộc của quốc sư @c1883","congNang":["Mở ra động phủ giới và sáng tạo một thế giới @c1883","Khi truyền ra ngoài, vô số động phủ giới cung cấp hương hỏa cho tộc quốc sư @c1883"],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1883","loai":"xuất hiện","importance":"major","giaiDoan":"Nguồn gốc được hé lộ","text":"Quốc sư tiết lộ thần thông mở động phủ giới vốn chỉ tộc hắn có, sau khi theo Tiên Tổ mới truyền ra cho các tông môn đủ tư cách trên Tiên Cương Đại Lục.","anchor":"Mở ra động phủ giới, thần thông thuật sáng tạo ra một thế giới trên thực tế là chỉ có tộc ta mới có!"}]},"capNhatToi":"@c1883","nguon":["@c1883"]},{"id":"phan-to-dai-phap","name":"Phản tổ đại pháp","cn":"","loai":"bi-thuat","loaiLabel":"Đại pháp","phamCap":"không rõ","hePhai":"Hoàng cung Tiên Tộc","soHuu":["Tiên Hoàng","Thượng Huyền Đạo"],"blurb":"Phản tổ đại pháp là đại pháp được Tiên Hoàng bố cục nhiều năm trong địa cung, nếu thành công có thể khiến người được chọn có được tu vi của Tiên Tổ. Tiên Hoàng chọn Minh Đạo Tôn làm đối tượng, trong khi quốc sư chọn Vương Lâm.","detail":"Trong địa cung, quốc sư tiết lộ rằng Phản tổ đại pháp là bố cục mà Tiên Hoàng chuẩn bị suốt nhiều năm. Mục đích của đại pháp là khiến người được chọn đạt được tu vi ngang Tiên Tổ, thực chất trở thành một Tiên Tổ thứ hai. Tiên Hoàng chọn Minh Đạo Tôn làm người thừa hưởng, còn quốc sư lại muốn dùng đại pháp này cho Vương Lâm.","congNang":["Khi thành công có thể khiến người được chọn có được tu vi của Tiên Tổ @c1883"],"nguonGoc":"Bố cục nhiều năm của Tiên Hoàng trong địa cung @c1883","dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1883","loai":"xuất hiện","importance":"major","giaiDoan":"Hai lựa chọn đối tượng","text":"Quốc sư tiết lộ Tiên Hoàng chọn Minh Đạo Tôn cho Phản tổ đại pháp, còn bản thân hắn chọn Vương Lâm.","anchor":"Phản tổ đại pháp này một khi thành công có thể khiến cho người khác có được tu vi của Tiên Tổ"}]},"capNhatToi":"@c1883","nguon":["@c1883"]},{"id":"huyet-the-cua-vuong-lam","name":"Huyết thệ của Vương Lâm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lời thề có điều kiện được Vương Lâm lập bằng một giọt máu chứa khí tức bản thân.","detail":"Vương Lâm nói mình không biết Tiên Cương thệ phù mà chỉ biết huyết thệ. Hắn lấy một giọt máu, hứa nếu lời quốc sư là thật thì sẽ giúp quốc sư một lần.","congNang":["Lập lời thề có điều kiện bằng máu của bản thân @c1884"],"dinhDanh":"goc","nguon":["@c1884"],"tabs":{"tienTrinh":[{"chuong":"@c1884","loai":"xuất hiện","importance":"normal","giaiDoan":"Lập huyết thệ","text":"Vương Lâm dùng giọt máu chứa khí tức bản thân để thay cho Tiên Cương thệ phù và đặt điều kiện nếu lời quốc sư là thật thì sẽ giúp một lần.","anchor":"Tại hạ không biết tiên cương thệ phù, chỉ biết huyết thệ"}]}},{"id":"khi-tuc-sat-luc-cua-vuong-lam","name":"Khí tức sát lục của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Sát lục","soHuu":["Vương Lâm"],"blurb":"Một tia khí tức sát lục được Vương Lâm bí mật thả vào ao máu để xâm nhập Minh Đạo Tôn.","detail":"Khi bước vào ao máu, Vương Lâm chuyển động chân phải, để một tia khí tức sát lục lan theo nước ao rồi chui vào cơ thể Minh Đạo Tôn. Biến cố này khiến Minh Đạo Tôn mở mắt và làm địa cung lạnh buốt.","congNang":["Xâm nhập cơ thể Minh Đạo Tôn qua nước ao @c1884"],"dinhDanh":"goc","nguon":["@c1884"],"tabs":{"tienTrinh":[{"chuong":"@c1884","loai":"thi triển","importance":"normal","giaiDoan":"Xâm nhập ao máu","text":"Vương Lâm bí mật thả khí tức sát lục theo nước ao để chui vào cơ thể Minh Đạo Tôn trước khi quốc sư thi triển bí thuật.","anchor":"Luồng khí tức vừa xuất hiện này lập tức lan theo nước áo"}]}},{"id":"huyet-the-khi-tuc","name":"Huyết thệ khí tức","cn":"","loai":"than-thong","loaiLabel":"Thần thông / thủ đoạn","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn dùng huyết thệ nổ thành huyết vụ mang khí tức Vương Lâm để đánh lạc hướng Minh Đạo Tôn.","detail":"Trong địa cung, Vương Lâm khiến huyết thệ nổ tung trước quốc sư, làm khí tức bản thân phủ lên quốc sư. Minh Đạo Tôn mất thần trí vì vậy nhận nhầm mục tiêu và chuyển sang công kích quốc sư.","congNang":["Ngụy trang và chuyển dời khí tức Vương Lâm lên mục tiêu khác để đánh lạc hướng kẻ đang truy sát @c1885"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1885","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1885","loai":"thi triển","importance":"normal","giaiDoan":"Đánh lạc hướng Minh Đạo Tôn","text":"Vương Lâm để huyết thệ nổ thành huyết vụ trước quốc sư, khiến Minh Đạo Tôn mất thần trí chuyển mục tiêu sang quốc sư.","anchor":"huyết thệ của Vương Lâm trước người quốc sư ầm ầm nổ tung"}]},"capNhatToi":"@c1885","nguon":["@c1885"]},{"id":"chin-luong-thanh-khi-cua-minh-dao-ton","name":"Chín luồng thanh khí của Minh Đạo Tôn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Minh Đạo Tôn"],"blurb":"Thần thông Minh Đạo Tôn điểm chỉ tạo ra chín luồng thanh khí, va chạm với sát lục hắc vụ của Vương Lâm.","detail":"Minh Đạo Tôn thi triển chín luồng thanh khí vờn quanh ngón tay, bộc phát khi va vào mây đen sát lục của Vương Lâm. Research ghi uy lực liên quan hỏa bổn nguyên tinh thuần.","thuocTinh":"hỏa bổn nguyên","uyLuc":"Bộc phát hỏa bổn nguyên tinh thuần khi va chạm với mây đen sát lục của Vương Lâm.","congNang":["Tạo chín luồng thanh khí quanh ngón tay để công kích và đối kháng hắc vụ sát lục @c1885"],"nguoiTu":[{"ten":"Minh Đạo Tôn","tuChuong":"@c1885","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1885","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng sát lục hắc vụ","text":"Minh Đạo Tôn điểm chỉ tạo chín luồng thanh khí, va chạm với mây đen sát lục của Vương Lâm.","anchor":"Lập tức chín luồng thanh khí đột nhiên xuất hiện, vờn quanh ngủ chi"}]},"capNhatToi":"@c1885","nguon":["@c1885"]},{"id":"dao-co-vo-tien-thuat","name":"Đạo cổ vô tiên thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm thi triển cùng Tàn Dạ để đánh Minh Đạo Tôn trong địa cung.","detail":"Khi Minh Đạo Tôn tỏa kim quang như mặt trời giáng xuống, Vương Lâm dùng tay phải thi triển Đạo cổ vô tiên thuật, phối hợp với Tàn Dạ ở tay trái để đánh ra hai thần thông cực mạnh cùng lúc.","congNang":["Phối hợp với Tàn Dạ thành thế công song trọng của Vương Lâm khi đối đầu Minh Đạo Tôn @c1885"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1885","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1885","loai":"thi triển","importance":"normal","giaiDoan":"Song thuật công kích Minh Đạo Tôn","text":"Vương Lâm thi triển Đạo cổ vô tiên thuật cùng Tàn Dạ để đối đầu Minh Đạo Tôn đang bộc phát kim quang.","anchor":"tay phải một chưởng một quyền, thi triển Đạo cổ vô tiên thuật"}]},"capNhatToi":"@c1885","nguon":["@c1885"]},{"id":"chin-than-anh-anh-trang-cua-quoc-su","name":"Chín thân ảnh ánh trắng của quốc sư","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Thượng Huyền Đạo"],"blurb":"Thần thông quốc sư phóng ra chín thân ảnh sáng trắng, hóa lớn thành chín chi vây công Minh Đạo Tôn.","detail":"Khi rời tế đàn giao chiến, quốc sư từ lòng bàn tay phải phóng ra chín thân ảnh tỏa ánh sáng trắng. Chúng hóa lớn rồi vây đánh Minh Đạo Tôn, phối hợp với thế công của Vương Lâm.","congNang":["Phóng chín thân ảnh ánh trắng hóa lớn để vây công đối thủ @c1885"],"nguoiTu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1885","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1885","loai":"thi triển","importance":"normal","giaiDoan":"Vây công Minh Đạo Tôn","text":"Quốc sư phóng chín thân ảnh ánh trắng từ lòng bàn tay phải, hóa lớn để vây công Minh Đạo Tôn.","anchor":"trong lòng bàn tay phải bất ngờ xuất hiện chín thân ảnh tỏa ra ánh sáng trắng"}]},"capNhatToi":"@c1885","nguon":["@c1885"]},{"id":"chuong-an-mau-vang","name":"Chưởng ấn màu vàng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại Thiên Tôn","hePhai":"","soHuu":[],"blurb":"Chưởng ấn màu vàng khổng lồ mang lực lượng hủy diệt cấp Đại Thiên Tôn, giáng xuống địa cung trong lúc hỗn chiến.","detail":"Chưởng ấn màu vàng từ bầu trời hoàng cung giáng xuống, phá vỡ địa cung và hư vô, kèm tiếng quát trách Thượng Huyền Đạo phản bội. Nó còn hấp thu kim quang từ Minh Đạo Tôn và Liên Đạo Phi khiến uy lực tăng mạnh.","uyLuc":"Ẩn chứa lực lượng hủy diệt thuộc về Đại Thiên Tôn và đủ sức phá địa cung.","congNang":["Giáng xuống như đòn hủy diệt cấp Đại Thiên Tôn, phá vỡ địa cung và uy hiếp mọi người bên dưới @c1885"],"tabs":{"tienTrinh":[{"chuong":"@c1885","loai":"thi triển","importance":"normal","giaiDoan":"Phá địa cung","text":"Chưởng ấn màu vàng giáng xuống địa cung, mang lực lượng hủy diệt Đại Thiên Tôn và lời quát trách Thượng Huyền Đạo phản bội.","anchor":"Trong chưởng ấn màu vàng nọ ẩn chứa lực lượng hủy diệt thuộc về Đại Thiên Tôn"}]},"capNhatToi":"@c1885","nguon":["@c1885"]},{"id":"thien-nguu-hon-khai","name":"Thiên Ngưu Hồn Khải","cn":"","loai":"than-thong","loaiLabel":"Hồn khải / thần thông hộ thân trợ chiến","phamCap":"không rõ","hePhai":"Thiên Ngưu","soHuu":["Vương Lâm"],"blurb":"Thiên Ngưu Hồn Khải là hồn khải được Vương Lâm kích phát tới đỉnh điểm trong trận vây công Minh Đạo Tôn, dung hợp lực Đạo cổ với tu vi để đánh ra một quyền hóa chín mươi chín hư ảnh hợp thành chân thân Thiên Ngưu, phát huy chiến lực đỉnh phong.","detail":"Thiên Ngưu Hồn Khải là một dạng hồn khải mà Vương Lâm sử dụng bằng cách kích phát tới đỉnh điểm, kết hợp lực Đạo cổ cùng tu vi bản thân. Khi triển khai toàn lực, nó cho phép đánh ra một quyền sinh ra chín mươi chín hư ảnh ngưng tụ hợp thành chân thân Thiên Ngưu, thể hiện chiến lực cực đại. Hồn khải này xuất hiện trong trận vây công Minh Đạo Tôn, là một trong những chiêu thức đỉnh phong Vương Lâm thi triển tại thời điểm đó.","congNang":["Tăng chiến lực đỉnh phong cho một quyền của Vương Lâm, dung hợp lực Đạo cổ với tu vi tạo chín mươi chín hư ảnh hợp thành chân thân Thiên Ngưu @c1886"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1886","tangDatToi":"kích phát tới đỉnh điểm","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1886","loai":"thi triển","importance":"normal","giaiDoan":"kích phát cực hạn","text":"Vương Lâm kích phát Thiên Ngưu Hồn Khải tới đỉnh điểm, dung hợp lực Đạo cổ với tu vi để đánh ra một quyền hóa chân thân Thiên Ngưu.","anchor":"toàn lực k*ch th*ch Thiên Ngưu Hồn Khải tới đỉnh điểm"}]},"capNhatToi":"@c1886","nguon":["@c1886"],"uyLuc":"Một quyền hóa chín mươi chín hư ảnh hợp thành chân thân Thiên Ngưu, phát huy trong trận vây công Minh Đạo Tôn.","dacDiem":"Cần kích phát tới đỉnh điểm và dung hợp lực Đạo cổ với tu vi mới phát huy toàn lực; biểu hiện dưới dạng chín mươi chín hư ảnh ngưng tụ thành chân thân Thiên Ngưu."},{"id":"thuat-nguoi-ti-hon-mau-trang-cua-quoc-su","name":"Thuật người tí hon màu trắng của quốc sư","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Nhất mạch của quốc sư","soHuu":["Thượng Huyền Đạo"],"blurb":"Thần thông do quốc sư thi triển để trói giữ Minh Đạo Tôn bằng sóng gợn.","detail":"Quốc sư phóng người tí hon màu trắng hóa thành thân ảnh lớn như chân thân, điểm một chỉ tạo sóng gợn như dây trói quấn Minh Đạo Tôn, khiến hắn khựng lại trong lúc bị vây công.","congNang":["Trói giữ mục tiêu bằng sóng gợn @c1886"],"nguoiTu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1886","tangDatToi":"thi triển trong giao chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1886","loai":"thi triển","importance":"normal","giaiDoan":"vây khốn Minh Đạo Tôn","text":"Quốc sư phóng người tí hon màu trắng, hóa thành thân ảnh lớn và dùng sóng gợn trói Minh Đạo Tôn.","anchor":"trong lòng bàn tay hắn có một người tí hon màu trắng hiện ra"}]},"capNhatToi":"@c1886","nguon":["@c1886"]},{"id":"huyet-nhan-cua-quoc-su","name":"Huyết nhân của quốc sư","cn":"","loai":"than-thong","loaiLabel":"Huyết thuật / thần thông","phamCap":"không rõ","hePhai":"Nhất mạch của quốc sư","soHuu":["Thượng Huyền Đạo"],"blurb":"Huyết thuật do quốc sư dùng máu và sinh mạng ngưng tụ huyết nhân để công kích Minh Đạo Tôn.","detail":"Huyết nhân đầu tiên bị huyết nhục Minh Đạo Tôn xuyên phá; huyết nhân sau dung hợp các thân ảnh lóe sáng và bộc phát uy áp lớn trong đợt vây công cuối.","congNang":["Tạo phân thân huyết sắc để công kích mục tiêu @c1886"],"nguoiTu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1886","tangDatToi":"ngưng tụ nhiều lần","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1886","loai":"thi triển","importance":"normal","giaiDoan":"huyết nhân vây công","text":"Quốc sư dùng máu tươi và sinh mạng ngưng tụ huyết nhân để cùng Vương Lâm vây công Minh Đạo Tôn.","anchor":"Máu tươi của hắn sau khi xuất hiện lập tức ngưng tụ lại một chỗ"}]},"capNhatToi":"@c1886","nguon":["@c1886"]},{"id":"truyen-thua-tien-to","name":"Truyền thừa Tiên Tổ","cn":"","loai":"khac","loaiLabel":"Truyền thừa","phamCap":"không rõ","hePhai":"Tiên tộc","soHuu":["Tiên Tổ Liên Vân Quyết","Thượng Huyền Đạo"],"blurb":"Truyền thừa Tiên Tổ là nghi thức tiếp nhận tu vi của Tiên Tổ, bề ngoài được quốc sư giới thiệu như cơ hội giúp Vương Lâm giải phong ấn cho tộc mình. Thực chất, quốc sư đã biến nó thành phương thức đoạt thân, lợi dụng sức mạnh Tiên Tổ trấn áp tâm thần và chiếm thần trí người nhận.","detail":"Quốc sư tuyên bố sẽ dùng sinh mệnh cuối cùng thi triển truyền thừa cho Vương Lâm, giúp hắn đạt tu vi truyền thừa của Tiên Tổ để giải khai phong ấn cho tộc mình. Tuy nhiên kế hoạch thực sự là mượn sức mạnh Tiên Tổ trong nghi thức này để trấn áp tâm thần Vương Lâm, chiếm đoạt thần trí hắn, từ đó thông qua thân thể Vương Lâm gián tiếp nắm giữ tu vi Tiên Tổ. Nghi thức bị quốc sư biến thành công cụ đoạt thân ẩn trong mắt phải đầu Tiên Tổ.","thuocTinh":"truyền thừa tu vi Tiên Tổ","uyLuc":"Có thể liên quan trực tiếp tới việc tiếp nhận tu vi Tiên Tổ, đồng thời đủ nguy hiểm để trấn áp tâm thần người nhận nếu bị thao túng.","dacDiem":"Bị quốc sư biến thành một nghi thức đoạt thân trong mắt phải đầu Tiên Tổ.","congNang":["Nhận tu vi truyền thừa của Tiên Tổ @c1887","Có thể bị lợi dụng để trấn áp tâm thần và chiếm thần trí người nhận @c1887"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1887","tangDatToi":"bị ép đưa vào nghi thức","trangThai":"bị tranh đoạt"}],"trangThai":"đang bị quốc sư thao túng","capNhatToi":"@c1887","tabs":{"tienTrinh":[{"chuong":"@c1887","loai":"xuất hiện","importance":"major","giaiDoan":"Quốc sư lộ kế hoạch truyền thừa","text":"Quốc sư nói muốn giúp Vương Lâm nhận truyền thừa Tiên Tổ, nhưng sau đó thừa nhận sẽ mượn sức mạnh Tiên Tổ để trấn áp tâm thần và chiếm thần trí hắn.","anchor":"Lão phu vốn có ý định giúp ngươi có được truyền thừa của Tiên Tổ"}]},"nguon":["@c1887"]},{"id":"truyen-thua-tu-vi-cua-tien-to","name":"Truyền thừa tu vi của Tiên Tổ","cn":"","loai":"cong-phap","loaiLabel":"Truyền thừa tu vi","phamCap":"Không rõ","hePhai":"Tiên Tổ","soHuu":["Tiên Tổ","Vương Lâm"],"blurb":"Truyền thừa bá đạo trong mắt phải Tiên Tổ, biểu hiện thành kim quang xâm nhập thân thể người nhận.","detail":"Kim quang truyền thừa cải tạo máu thịt, xương cốt và có thể phá hủy ý chí phản kháng. Thượng Huyền Đạo lợi dụng đặc tính này để trấn áp tâm thần Vương Lâm, chuẩn bị đoạt thân và giải phong ấn Điệu Vong tộc.","thuocTinh":"kim quang truyền thừa","uyLuc":"Có thể cải tạo thân thể và trấn áp ý chí người nhận truyền thừa.","dacDiem":"Bá đạo, lan khắp thân thể người nhận, nhưng không lấn át được hồn huyết Cổ Tổ trong Vương Lâm.","congNang":["Cải tạo thân thể người nhận truyền thừa trong mắt phải Tiên Tổ @c1888","Trấn áp ý chí và tâm thần người nhận, bị Thượng Huyền Đạo lợi dụng để đoạt thân @c1888"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1888","tangDatToi":"bị truyền thừa xâm chiếm","trangThai":"bị động tiếp nhận"},{"ten":"Thượng Huyền Đạo","tuChuong":"@c1888","tangDatToi":"mượn truyền thừa để trấn áp linh hồn","trangThai":"lợi dụng"}],"tabs":{"tienTrinh":[{"chuong":"@c1888","loai":"xuất hiện","importance":"normal","giaiDoan":"Kim quang xâm chiếm","text":"Truyền thừa tu vi của Tiên Tổ lộ tính chất bá đạo khi kim quang cải tạo thân thể Vương Lâm và bị Thượng Huyền Đạo dùng để trấn áp tâm thần hắn.","anchor":"trên thực tế mục đích là muốn mượn sự truyền thừa tu vi bá đạo của Tiên Tổ"}]},"capNhatToi":"@c1888","nguon":["@c1888"]},{"id":"linh-hon-hoa-hu","name":"Linh hồn hóa hư","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thượng Huyền Đạo","soHuu":["Thượng Huyền Đạo"],"blurb":"Thần thông Thượng Huyền Đạo dùng trong cơ thể Vương Lâm để làm dao động linh hồn hóa hư.","detail":"Khi tìm thấy một dao động linh hồn yếu ớt trong thân thể Vương Lâm, Thượng Huyền Đạo niệm chú và khiến nó tan thành mây khói, từ đó tin rằng linh hồn Vương Lâm đã bị xóa sạch.","uyLuc":"Làm dao động linh hồn bị phát hiện tan biến thành hư vô.","congNang":["Làm linh hồn hóa hư và tan thành mây khói @c1888"],"nguoiTu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1888","tangDatToi":"thi triển trong cơ thể Vương Lâm","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1888","loai":"thi triển","importance":"normal","giaiDoan":"Xóa dao động linh hồn","text":"Thượng Huyền Đạo dùng Linh hồn hóa hư để khiến dao động linh hồn mà hắn phát hiện trong cơ thể Vương Lâm tan biến.","anchor":"Tất cả mọi vật tồn tại, bởi có nhân tồn tại nên có thể thành Vô! Linh hồn. hóa hư!"}]},"capNhatToi":"@c1888","nguon":["@c1888"]},{"id":"chu-ngu-mo-mat-trai-tien-to","name":"Chú ngữ mở mắt trái Tiên Tổ","cn":"","loai":"bi-thuat","loaiLabel":"Chú ngữ","phamCap":"Không rõ","hePhai":"Thượng Huyền Đạo","soHuu":["Thượng Huyền Đạo"],"blurb":"Chú ngữ được Thượng Huyền Đạo phát ra sau khi chiếm thân thể Vương Lâm, dùng để mở mắt trái Tiên Tổ.","detail":"Thượng Huyền Đạo bắt quyết và niệm hàng loạt chú ngữ, khiến mắt trái Tiên Tổ mở ra. Sau khi mở, mắt trái sinh ra lực hút kéo Liên Đạo Phi khỏi tế đàn và nuốt vào trong thế giới mắt trái.","uyLuc":"Mở mắt trái Tiên Tổ và tạo lực hút kéo người bị khóa trên tế đàn.","congNang":["Mở mắt trái Tiên Tổ @c1888","Tạo lực hút kéo Liên Đạo Phi khỏi tế đàn và nuốt vào mắt trái @c1888"],"nguoiTu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1888","tangDatToi":"thi triển thành công","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1888","loai":"thi triển","importance":"normal","giaiDoan":"Mở mắt trái","text":"Thượng Huyền Đạo phát chú ngữ trong thân thể Vương Lâm, khiến mắt trái Tiên Tổ mở ra và hút Liên Đạo Phi vào.","anchor":"trong tiếng gầm nhẹ liền phát ra hàng loạt chú ngữ"}]},"capNhatToi":"@c1888","nguon":["@c1888"]},{"id":"thuat-dac-biet-cua-dieu-vong-to","name":"Thuật đặc biệt của Điệu vong tổ","cn":"","loai":"than-thong","loaiLabel":"Thuật pháp","phamCap":"Không rõ","hePhai":"Điệu vong tổ","soHuu":["Thượng Huyền Đạo"],"blurb":"Thuật được quốc sư dùng để khiến đầu tiên tổ mở miệng, nhằm gỡ phong ấn cho tộc mình.","detail":"Trong kế hoạch của quốc sư, thuật đặc biệt của Điệu vong tổ là then chốt để lợi dụng đầu tiên tổ đã mở hai mắt, ép cái đầu phát ra lời giải phong ấn cho toàn tộc.","congNang":["Khiến đầu tiên tổ mở miệng để phục vụ nghi thức giải phong ấn @c1889"],"nguoiTu":[{"ten":"Thượng Huyền Đạo","tuChuong":"@c1889","tangDatToi":"","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1889","loai":"thi triển","importance":"normal","giaiDoan":"Mở miệng đầu Tiên Tổ","text":"Quốc sư dùng thuật đặc biệt của Điệu vong tổ khiến đầu tiên tổ mở miệng, nhưng lời cuối bị Tiên hoàng chặn lại.","anchor":"ngươi dùng thuật đặc biệt của Điệu vong tổ khiến cho tiên tổ mở miệng"}]},"dinhDanh":"goc","capNhatToi":"@c1889","nguon":["@c1889"]},{"id":"tu-lam-tin-thuat","name":"Tử Lâm Tín Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thuật mạnh nhất của Song Tử","hePhai":"Song Tử Đại Thiên Tôn","soHuu":["Song Tử Đại Thiên Tôn"],"blurb":"Thần thông mạnh nhất của Song Tử Đại Thiên Tôn, thi triển sau khi hai thân thể hợp nhất.","detail":"Tử Lâm Tín Thuật khiến tử quang bao phủ cấm cung và tổ thành, dẫn xuống thiên thạch màu tím khổng lồ, dùng sức ép phá nát tổ thành để buộc Tiên hoàng giao Vương Lâm.","uyLuc":"Bao phủ tổ thành và dẫn thiên thạch tím có thể uy hiếp phá nát tổ thành.","congNang":["Tạo tử quang bao phủ chiến trường và tổ thành @c1889","Dẫn thiên thạch màu tím khổng lồ xuống để uy hiếp phá nát tổ thành @c1889"],"nguoiTu":[{"ten":"Song Tử Đại Thiên Tôn","tuChuong":"@c1889","tangDatToi":"Thi triển sau hợp thể","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1889","loai":"thi triển","importance":"normal","giaiDoan":"Uy hiếp Tổ Thành","text":"Song Tử hợp thể thành nữ tử áo trắng rồi thi triển Tử Lâm Tín Thuật, dùng thiên thạch tím ép Tiên hoàng giao Vương Lâm.","anchor":"Tử Lâm Tín Thuật, thuật mạnh nhất của Song Tử ngươi"}]},"dinhDanh":"goc","capNhatToi":"@c1889","nguon":["@c1889"]},{"id":"kiem-anh-mau-tim-cua-song-tu","name":"Kiếm ảnh màu tím của Song Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"Không rõ","hePhai":"Song Tử Đại Thiên Tôn","soHuu":["Song Tử Đại Thiên Tôn"],"blurb":"Công kích do Song Tử Đại Thiên Tôn phóng ra từ tử dương, hợp thành kiếm quang màu tím.","detail":"Hai kiếm ảnh màu tím dung hợp thành một đạo kiếm quang công kích Tiên hoàng, nhưng khi chạm kim quang trong mắt đầu tiên tổ thì lập tức sụp đổ.","uyLuc":"Có thể công kích trong giao chiến Đại Thiên Tôn, nhưng bị kim quang đầu tiên tổ phá tan.","congNang":["Dung hợp hai kiếm ảnh thành kiếm quang màu tím để công kích @c1889"],"nguoiTu":[{"ten":"Song Tử Đại Thiên Tôn","tuChuong":"@c1889","tangDatToi":"","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1889","loai":"thi triển","importance":"normal","giaiDoan":"Công kích Tiên hoàng","text":"Song Tử dung hợp hai kiếm ảnh tím thành kiếm quang công kích, nhưng bị kim quang đầu tiên tổ đánh sụp.","anchor":"hai kiếm ảnh này dung hợp với nhau, hóa thành một đạo kiếm quang"}]},"dinhDanh":"goc","capNhatToi":"@c1889","nguon":["@c1889"]},{"id":"tien-hoa-dao","name":"Tiên Hỏa Đạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đạo thuật / thần thông","phamCap":"Không rõ","hePhai":"Tiên tộc","soHuu":["Tiên Hoàng"],"blurb":"Đạo thuật phát ra từ đầu lâu Tiên Tổ dưới sự điều khiển của Tiên Hoàng, tạo chín vòng khói xanh bức lui Đại Thiên Tôn.","detail":"Khi Tiên Hoàng điều động đầu lâu Tiên Tổ, giọng nói từ đầu lâu gọi Tiên Hỏa Đạo, chín vòng khói xanh lớn cỡ một trượng lao về phía Song Tử và Cửu Đế.","uyLuc":"Bức lui Cửu Đế và Song Tử trong lần giao phong đầu ở cấm cung.","congNang":["Tạo chín vòng khói xanh lao tới đối thủ @c1890"],"nguoiTu":[{"ten":"Tiên Hoàng","tuChuong":"@c1890","tangDatToi":"Không rõ","trangThai":"mượn đầu lâu Tiên Tổ thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1890","loai":"thi triển","importance":"normal","giaiDoan":"Chín vòng khói xanh","text":"Tiên Hỏa Đạo hiện ra từ đầu lâu Tiên Tổ, tạo chín vòng khói xanh khiến Cửu Đế và Song Tử phải lui.","anchor":"chín vòng khói xanh lớn cỡ một trượng đột nhiên xuất hiện"}]},"capNhatToi":"@c1890","nguon":["@c1890"]},{"id":"dao-cua-dao-nhat","name":"Đạo của Đạo Nhất","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đạo pháp","phamCap":"Không rõ","hePhai":"Tiên tộc","soHuu":["Đạo Nhất Đại Thiên Tôn"],"blurb":"Đạo pháp của Đạo Nhất Đại Thiên Tôn, lấy vạn vật hóa nhất làm cốt lõi.","detail":"Trong trận đối kháng kim kiếm Tiên Tổ, Đạo Nhất dồn lực lượng đỉnh phong toàn thân vào một chỉ, đại biểu đạo vạn vật hóa nhất đánh về phía Tiên Hoàng.","congNang":["Gom vạn vật hóa nhất vào một chỉ công kích @c1890"],"nguoiTu":[{"ten":"Đạo Nhất Đại Thiên Tôn","tuChuong":"@c1890","tangDatToi":"đỉnh phong","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1890","loai":"thi triển","importance":"normal","giaiDoan":"Một chỉ hóa nhất","text":"Đạo Nhất dùng một chỉ đại biểu đạo vạn vật hóa nhất để công kích Tiên Hoàng.","anchor":"Đạo của hắn là vạn vật hóa nhất"}]},"capNhatToi":"@c1890","nguon":["@c1890"]},{"id":"vo-dao-cua-vo-phong","name":"Võ đạo của Võ Phong","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đạo pháp / võ đạo","phamCap":"Không rõ","hePhai":"Tiên tộc","soHuu":["Võ Phong Đại Thiên Tôn"],"blurb":"Võ đạo của Võ Phong Đại Thiên Tôn, lấy dùng võ nhập đạo làm căn bản.","detail":"Võ Phong tung một quyền chứa toàn bộ lực lượng, cảm ngộ thiên địa và tín niệm đỉnh phong để cùng các Đại Thiên Tôn đối kháng kim kiếm Tiên Tổ.","congNang":["Dùng một quyền ngưng tụ võ đạo, lực lượng và tín niệm đỉnh phong @c1890"],"nguoiTu":[{"ten":"Võ Phong Đại Thiên Tôn","tuChuong":"@c1890","tangDatToi":"đỉnh phong","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1890","loai":"thi triển","importance":"normal","giaiDoan":"Một quyền nhập đạo","text":"Võ Phong dùng võ nhập đạo, tung một quyền hội tụ toàn bộ lực lượng và cảm ngộ của mình.","anchor":"Hắn cầu võ đạo, dùng võ nhập đạo"}]},"capNhatToi":"@c1890","nguon":["@c1890"]},{"id":"bach-lang-trong-mat-troi-trang-cua-cuu-de","name":"Bạch lang trong mặt trời trắng của Cửu Đế","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên tộc","soHuu":["Cửu Đế Đại Thiên Tôn"],"blurb":"Thần thông Cửu Đế dùng trong lúc đối kháng thanh kiếm vàng của hư ảnh Tiên Tổ.","detail":"Cửu Đế biến ra mặt trời màu trắng, từ đó hiện một con bạch lang gầm thét để nghênh kích kim kiếm vàng chém xuống.","uyLuc":"Tham gia hợp lực phá kim kiếm chỉ chứa một thành lực lượng Tiên Tổ.","congNang":["Biến ra bạch lang từ mặt trời trắng để đối kháng kim kiếm Tiên Tổ @c1890"],"nguoiTu":[{"ten":"Cửu Đế Đại Thiên Tôn","tuChuong":"@c1890","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1890","loai":"thi triển","importance":"normal","giaiDoan":"Nghênh kích kim kiếm","text":"Cửu Đế dùng mặt trời trắng và bạch lang đối kháng kim kiếm vàng của hư ảnh Tiên Tổ.","anchor":"một con bạch lang gầm thét từ trong mặt trời màu trắng biến ảo ra"}]},"capNhatToi":"@c1890","nguon":["@c1890"]},{"id":"tu-truc-rung-kiem-cua-song-tu","name":"Tử trúc rừng kiếm của Song Tử","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên tộc","soHuu":["Song Tử Đại Thiên Tôn"],"blurb":"Thần thông Song Tử dùng tử khí hóa rừng trúc tím như vạn kiếm để nghênh kích kim kiếm Tiên Tổ.","detail":"Khi kim kiếm vàng chém xuống, Song Tử dùng tử khí tạo thành vùng trúc tím, chớp mắt hóa thành rừng trúc như vạn kiếm đồng thời đâm tới.","uyLuc":"Tham gia hợp lực phá kim kiếm chỉ chứa một thành lực lượng Tiên Tổ.","congNang":["Hóa tử khí thành rừng trúc tím như vạn kiếm để công kích @c1890"],"nguoiTu":[{"ten":"Song Tử Đại Thiên Tôn","tuChuong":"@c1890","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1890","loai":"thi triển","importance":"normal","giaiDoan":"Rừng trúc vạn kiếm","text":"Song Tử dùng tử khí hóa thành rừng trúc tím như vạn kiếm để đối kháng kim kiếm vàng.","anchor":"tạo thành một rừng trúc, giống như vạn kiếm đồng thời đâm tới"}]},"capNhatToi":"@c1890","nguon":["@c1890"]},{"id":"giai-khai-phong-an-dieu-vong-toc","name":"Giải khai phong ấn Điệu Vong Tộc","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Nghi thức phép tắc","phamCap":"không rõ","hePhai":"Tiên hoàng nhất mạch","soHuu":["Tiên Hoàng"],"blurb":"Nghi thức Tiên Hoàng dùng máu thịt hậu nhân Tiên Tổ để dẫn động phép tắc Thiên Cương, vĩnh viễn giải khai phong ấn chủng tộc của Điệu Vong Tộc và kéo theo chuỗi biến cố khiến quốc sư chân chính thức tỉnh.","detail":"Tiên Hoàng thi triển nghi thức này trong lúc kim quang bên ngoài sắp bị bốn Đại Thiên Tôn phá vỡ. Điều kiện bắt buộc là Tiên Hoàng phải dùng chính máu thịt hậu nhân Tiên Tổ làm dẫn; cái giá thể hiện ngay trên thân thể hắn khi ngón tay, bàn tay và nửa cánh tay phải tan vỡ. Kết quả là phong ấn Điệu Vong Tộc bị giải khai vĩnh viễn, đồng thời kích hoạt chuỗi biến cố khiến quốc sư giả bị diệt và Hải Tử thức tỉnh thân phận quốc sư thật.","thuocTinh":"phép tắc Thiên Cương, máu thịt hậu nhân Tiên Tổ","uyLuc":"Có thể giải khai phong ấn chủng tộc của Điệu Vong Tộc.","dacDiem":"Cần Tiên Hoàng dùng chính máu thịt hậu nhân Tiên Tổ làm dẫn.","congNang":["Giải khai phong ấn Điệu Vong Tộc vĩnh viễn @c1891","Kích hoạt chuỗi biến cố khiến quốc sư giả bị diệt và Hải Tử thức tỉnh thân phận quốc sư thật @c1891"],"nguoiTu":[{"ten":"Tiên Hoàng","tuChuong":"@c1891","tangDatToi":"thi triển nghi thức","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1891","loai":"xuất hiện","importance":"major","giaiDoan":"Giải phong ấn","text":"Tiên Hoàng dùng máu thịt hậu nhân Tiên Tổ dẫn động phép tắc Thiên Cương để giải khai phong ấn Điệu Vong Tộc.","anchor":"Lấy máu thịt hậu nhân Tiên Tổ của ta. dẫn động phép tắc Thiên Cương"}]},"trangThai":"đã thi triển @c1891","capNhatToi":"@c1891","dinhDanh":"goc","nguon":["@c1891"]},{"id":"dieu-vong-chi-luc-cua-quoc-su-chan-chinh","name":"Điệu Vong chi lực của quốc sư chân chính","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông huyết mạch truyền thừa","phamCap":"không rõ","hePhai":"Điệu Vong Tộc","soHuu":["Hải Tử Thiên Tôn"],"blurb":"Sức mạnh quốc sư chân chính của Điệu Vong Tộc, thức tỉnh trên người Hải Tử. Nó thu hồi kim quang quanh đầu Tiên Tổ và cắt đứt quá trình Tiên Hoàng hấp thu truyền thừa.","detail":"Sau khi phong ấn Điệu Vong Tộc biến mất, Hải Tử thức tỉnh sức mạnh vốn thuộc về quốc sư chân chính của tộc này. Lực lượng ấy gắn liền với ý nghĩa Điệu Vong — lấy suy nghĩ của người sống và sự tồn tại của người chết làm nền tảng. Khi phát động, kim quang quanh đầu Tiên Tổ co rút trở về, hai mắt đầu Tiên Tổ khép lại, và nguồn sức mạnh màu vàng đang truyền vào Tiên Hoàng bị cắt đứt hoàn toàn.","thuocTinh":"Điệu Vong Tộc, quốc sư chân chính","uyLuc":"Có thể ảnh hưởng trực tiếp tới kim quang quanh đầu Tiên Tổ và ngăn Tiên Hoàng hấp thu truyền thừa.","dacDiem":"Gắn với ý nghĩa Điệu Vong, lấy suy nghĩ của người sống và sự tồn tại của người chết làm nền.","congNang":["Thu hồi kim quang quanh đầu Tiên Tổ @c1891","Cắt đứt quá trình Tiên Hoàng hấp thu truyền thừa Tiên Tổ @c1891"],"nguoiTu":[{"ten":"Hải Tử Thiên Tôn","tuChuong":"@c1891","tangDatToi":"mới thức tỉnh","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1891","loai":"xuất hiện","importance":"major","giaiDoan":"Quốc sư thật thức tỉnh","text":"Hải Tử thức tỉnh sức mạnh quốc sư chân chính của Điệu Vong Tộc và dùng nó cắt đứt thế hấp thu của Tiên Hoàng.","anchor":"Điệu Vong Tộc, lấy suy nghĩ của người sống, lấy sự tồn tại của người chết"}]},"trangThai":"đang hiện hữu @c1891","capNhatToi":"@c1891","dinhDanh":"goc","nguon":["@c1891"]},{"id":"than-thong-bon-toc-dieu-vong-toc","name":"Thần thông bổn tộc Điệu Vong Tộc","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Truyền thừa bổn tộc","phamCap":"không rõ","hePhai":"Điệu Vong Tộc","soHuu":["Quốc sư giả của Điệu Vong Tộc","Quốc sư đời thứ nhất của Điệu Vong Tộc"],"blurb":"Thần thông của Điệu Vong Tộc từng được quốc sư đời thứ nhất truyền cho người được đưa lên làm quốc sư giả. Đây là một phần truyền thừa giúp hắn gánh vỏ bọc quốc sư.","detail":"Trong ký ức hồi tỉnh trước khi chết, quốc sư giả nhớ lại nữ tử quốc sư đời thứ nhất đã đưa hắn lên làm quốc sư và truyền thụ thần thông bổn tộc cho hắn.","nguonGoc":"Điệu Vong Tộc","congNang":["Là thần thông truyền thừa của Điệu Vong Tộc được truyền cho quốc sư giả @c1891"],"nguoiTu":[{"ten":"Quốc sư giả của Điệu Vong Tộc","tuChuong":"@c1891","tangDatToi":"được truyền thụ","trangThai":"đã mất theo người tu"},{"ten":"Quốc sư đời thứ nhất của Điệu Vong Tộc","tuChuong":"@c1891","tangDatToi":"người truyền thụ","trangThai":"đã qua đời"}],"tabs":{"tienTrinh":[{"chuong":"@c1891","loai":"xuất hiện","importance":"normal","giaiDoan":"Ký ức quốc sư giả","text":"Quốc sư giả nhớ lại mình từng được quốc sư đời thứ nhất truyền thụ thần thông bổn tộc Điệu Vong Tộc.","anchor":"hắn đã được nữ tử kia đưa lên làm quốc sư, truyền thụ cho hắn thần thông"}]},"trangThai":"được nhắc qua ký ức @c1891","capNhatToi":"@c1891","dinhDanh":"goc","nguon":["@c1891"]},{"id":"tro-thuat-cua-tien-to","name":"Trớ thuật của Tiên Tổ","cn":"","loai":"bi-thuat","loaiLabel":"Nguyền rủa huyết mạch","phamCap":"không rõ","hePhai":"Tiên Tổ","soHuu":["Tiên Tổ Liên Vân Quyết"],"blurb":"Trớ thuật của Tiên Tổ là lời nguyền bảo hộ thi thể Tiên Tổ sau khi chết, khiến bất kỳ kẻ nào muốn hủy diệt thân thể đều phải chết. Con đường duy nhất phá giải là hậu nhân dùng huyết mạch lực thí tổ, đổi lấy đại giá cắt đứt truyền thừa huyết mạch.","detail":"Theo lời Cửu Đế giải thích, thân thể Tiên Tổ sau khi chết chịu sự che chở của trớ thuật này. Mọi kẻ toan hủy diệt thi thể đều bị trớ thuật giáng chết. Phương thức phá giải duy nhất đòi hỏi hậu nhân trực hệ của Tiên Tổ tự nguyện dùng huyết mạch lực để thí tổ, chịu trớ thuật nhập thân, cái giá là vĩnh viễn chặt đứt huyết mạch liên hệ với Tiên Tổ — đồng nghĩa xóa bỏ truyền thừa.","thuocTinh":"nguyền rủa huyết mạch","uyLuc":"Ngăn mọi kẻ hủy diệt thân thể Tiên Tổ bằng cái chết, chỉ mở lối qua huyết mạch hậu nhân.","dacDiem":"Phá giải đồng nghĩa cắt đứt truyền thừa huyết mạch Tiên Tổ.","congNang":["Ngăn mọi kẻ hủy diệt thân thể Tiên Tổ sau khi chết bằng cái chết giáng xuống kẻ đó @c1892","Buộc hậu nhân dùng huyết mạch lực thí tổ nếu muốn phá giải, chịu đại giá cắt đứt huyết mạch @c1892"],"nguoiTu":[{"ten":"Tiên Tổ Liên Vân Quyết","tuChuong":"@c1892","tangDatToi":"không rõ","trangThai":"nguồn gốc trớ thuật"}],"tabs":{"tienTrinh":[{"chuong":"@c1892","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ cơ chế","text":"Cửu Đế giải thích trớ thuật khiến thân thể Tiên Tổ sau khi chết không thể bị hủy diệt nếu không có hậu nhân dùng huyết mạch lực thí tổ.","anchor":"Nếu Tiên Tổ chết, thì thân thể của hắn sẽ bị nguyền rủa"}]},"capNhatToi":"@c1892","nguon":["@c1892"]},{"id":"luc-luong-bi-mat-dieu-vong-toc","name":"Lực lượng bí mật Điệu Vong Tộc","cn":"","loai":"than-thong","loaiLabel":"Bố trí kích hoạt linh miếu","phamCap":"không rõ","hePhai":"Điệu Vong tộc","soHuu":["Hải Tử Thiên Tôn","Điệu Vong tộc"],"blurb":"Lực lượng bí mật do Điệu Vong Tộc đời đời chuẩn bị để kích hoạt linh miếu trên bảy mươi hai châu. Hải Tử dùng nó làm đòn ép Tiên hoàng kế thừa Tiên Tổ và giải phong ấn.","detail":"Nếu Tiên hoàng bỏ qua truyền thừa Tiên Tổ, Hải Tử có thể phát động lực lượng bí mật của Điệu Vong Tộc. Khi đó linh miếu trên bảy mươi hai châu tiên tộc nghe hiệu lệnh nàng, đánh thức linh hồn bị phong ấn và làm chấn động sức trấn áp của đầu Tiên Tổ.","thuocTinh":"linh miếu, linh hồn phong ấn","uyLuc":"Có thể gây đại loạn trên phạm vi bảy mươi hai châu tiên tộc.","congNang":["Kích hoạt linh miếu bảy mươi hai châu theo hiệu lệnh của Hải Tử @c1892","Đánh thức linh hồn bị phong ấn để chấn động sức trấn áp của đầu Tiên Tổ @c1892"],"tabs":{"tienTrinh":[{"chuong":"@c1892","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hải Tử tuyên bố","text":"Hải Tử nói lực lượng bí mật Điệu Vong Tộc sẽ phát động nếu Tiên hoàng không nhận truyền thừa Tiên Tổ.","anchor":"lực lượng bí mật Điệu Vong Tộc ta đời đời chuẩn bị sẽ được phát động"}]},"capNhatToi":"@c1892","nguon":["@c1892"]},{"id":"thinh-dao-cua-hai-tai-tien-to","name":"Thính đạo của hai tai Tiên Tổ","cn":"","loai":"than-thong","loaiLabel":"Đạo cảm ngộ phép tắc","phamCap":"không rõ","hePhai":"Tiên Tổ","soHuu":["Võ Phong Đại Thiên Tôn"],"blurb":"Khả năng thính đạo gắn với hai tai Tiên Tổ, được Cửu Đế hứa giao cho Vũ Phong. Khi dung nhập vào đạo, nó có thể giúp nghe quỹ tích vận chuyển phép tắc Tiên Cương.","detail":"Cửu Đế nói hai tai Tiên Tổ có thể nghe quỹ tích vận chuyển của phép tắc Tiên Cương. Nếu Vũ Phong dung nhập vật này vào đạo của mình, hắn có thể cảm thụ đỉnh của đạo theo lời dụ dỗ của Cửu Đế.","thuocTinh":"thính đạo","uyLuc":"Giúp cảm nhận quỹ tích phép tắc Tiên Cương.","congNang":["Nghe quỹ tích vận chuyển phép tắc Tiên Cương @c1892"],"nguoiTu":[{"ten":"Võ Phong Đại Thiên Tôn","tuChuong":"@c1892","tangDatToi":"dự kiến dung nhập","trangThai":"được hứa giao hai tai Tiên Tổ"}],"tabs":{"tienTrinh":[{"chuong":"@c1892","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Cửu Đế hứa lợi","text":"Cửu Đế hứa hai tai Tiên Tổ cho Vũ Phong để dung nhập vào đạo và nghe phép tắc Tiên Cương.","anchor":"nghe được quỹ tích vận chuyện của phép tắc Tiên Cương"}]},"capNhatToi":"@c1892","nguon":["@c1892"]},{"id":"huyet-mach-tien-hoang-truyen-vao-dau-lau-tien-to","name":"Huyết mạch Tiên Hoàng truyền vào đầu lâu Tiên Tổ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Huyết mạch/thần thông","phamCap":"Không rõ","hePhai":"Tiên tộc","soHuu":["Tiên Hoàng"],"blurb":"Tiên Hoàng vận dụng lực huyết mạch để tác động lên đầu lâu Tiên Tổ, khiến đầu lâu nứt và thất khiếu phun sương vàng kim.","detail":"Trong lúc tranh đoạt đầu lâu Tiên Tổ, Tiên Hoàng dùng lực huyết mạch chém nứt rồi truyền vào đầu lâu, tạo điều kiện cho màn giả hấp thu và kế tự bạo thân thể.","thuocTinh":"Huyết mạch Tiên tộc","uyLuc":"Có thể kích hoạt dị biến của đầu lâu Tiên Tổ và dẫn ra sương vàng kim từ thất khiếu.","dacDiem":"Gắn trực tiếp với huyết mạch của Tiên Hoàng và di hài Tiên Tổ.","congNang":["Kích hoạt đầu lâu Tiên Tổ, khiến thất khiếu phun sương vàng kim @c1893"],"nguoiTu":[{"ten":"Tiên Hoàng","tuChuong":"@c1893","tangDatToi":"Không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1893","loai":"thi triển","importance":"normal","giaiDoan":"Kích hoạt đầu lâu Tiên Tổ","text":"Tiên Hoàng thúc lực huyết mạch tràn ra để tác động lên đầu lâu Tiên Tổ.","anchor":"Lực lượng huyết mạch trong cơ thể hắn ầm ầm tràn ra"}]},"capNhatToi":"@c1893","nguon":["@c1893"]},{"id":"dai-thien-ton-tu-bao","name":"Đại Thiên Tôn tự bạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông tự hủy thân thể","phamCap":"Đại Thiên Tôn","hePhai":"Không rõ","soHuu":["Tiên Hoàng"],"blurb":"Phương thức tự hủy thân thể của Tiên Hoàng, tạo ra xung kích cực lớn giữa hoàng cung Tiên tộc.","detail":"Tiên Hoàng chủ động tự bạo thân thể Đại Thiên Tôn, làm lực lượng hủy diệt hòa với thần thông của Cửu Đế, Đạo Nhất và Võ Phong, phá cấm cung, địa cung và lan tới hoàng cung.","uyLuc":"Phá hủy không gian hoàng cung, quét qua cấm cung và địa cung, đồng thời kéo ba Đại Thiên Tôn vào hệ quả phản phệ.","dacDiem":"Tự bạo thân thể nhưng linh hồn Tiên Hoàng vẫn còn tồn tại để tìm đường đoạt xá.","congNang":["Tạo lực tự hủy thân thể cấp Đại Thiên Tôn, gây xung kích diện rộng @c1893"],"nguoiTu":[{"ten":"Tiên Hoàng","tuChuong":"@c1893","tangDatToi":"Tự bạo thân thể","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1893","loai":"thi triển","importance":"normal","giaiDoan":"Tự bạo thân thể","text":"Tiên Hoàng tự bạo thân thể Đại Thiên Tôn, khiến lực nổ lan ra hoàng cung và cuốn thần thông của ba Đại Thiên Tôn vào cùng một tai họa.","anchor":"Đại Thiên Tôn tự bạo, dù chỉ là thân thể nổ tung"}]},"capNhatToi":"@c1893","nguon":["@c1893"]},{"id":"chuong-an-cua-dao-nhat","name":"Chưởng ấn của Đạo Nhất","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại Thiên Tôn","hePhai":"Đạo của Đạo Nhất","soHuu":["Đạo Nhất Đại Thiên Tôn"],"blurb":"Đòn chưởng ấn do Đạo Nhất tung ra khi cùng các Đại Thiên Tôn công kích Tiên Hoàng.","detail":"Đạo Nhất giơ tay phải hóa thành chưởng ấn đánh vào thân thể Tiên Hoàng, nhưng đòn này bị cuốn vào vụ tự bạo và trở thành một phần nguyên nhân khiến hắn bị Trớ Thuật phản phệ.","uyLuc":"Dùng để công kích tồn tại cấp Đại Thiên Tôn.","congNang":["Hóa tay phải thành chưởng ấn công kích mục tiêu @c1893"],"nguoiTu":[{"ten":"Đạo Nhất Đại Thiên Tôn","tuChuong":"@c1893","tangDatToi":"Thi triển","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1893","loai":"thi triển","importance":"normal","giaiDoan":"Công kích Tiên Hoàng","text":"Đạo Nhất hóa tay phải thành chưởng ấn để đánh Tiên Hoàng trong lúc biến cố đầu lâu Tiên Tổ bùng phát.","anchor":"liền giơ tay phải lên. hóa thành một chưởng ấn"}]},"capNhatToi":"@c1893","nguon":["@c1893"]},{"id":"mot-quyen-cua-vo-phong","name":"Một quyền của Võ Phong","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại Thiên Tôn","hePhai":"Võ đạo của Võ Phong","soHuu":["Võ Phong Đại Thiên Tôn"],"blurb":"Quyền kích của Võ Phong trong lúc phối hợp Đạo Nhất và Cửu Đế đánh Tiên Hoàng.","detail":"Võ Phong đồng thời ra tay công kích Tiên Hoàng, nhưng quyền lực bị nhập vào huyết nhục tự bạo của Tiên Hoàng và khiến tai họa lan rộng hơn.","uyLuc":"Dùng để công kích tồn tại cấp Đại Thiên Tôn.","congNang":["Tung quyền công kích mục tiêu trong giao chiến cấp Đại Thiên Tôn @c1893"],"nguoiTu":[{"ten":"Võ Phong Đại Thiên Tôn","tuChuong":"@c1893","tangDatToi":"Thi triển","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1893","loai":"thi triển","importance":"normal","giaiDoan":"Công kích Tiên Hoàng","text":"Võ Phong đồng thời ra tay đánh Tiên Hoàng, khiến quyền lực bị cuốn vào vụ tự bạo kế tiếp.","anchor":"Cùng lúc đó Võ Phong cũng đồng thời ra tay"}]},"capNhatToi":"@c1893","nguon":["@c1893"]},{"id":"bach-lang-huyen-hoa-cua-cuu-de","name":"Bạch lang huyễn hóa của Cửu Đế","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông huyễn hóa","phamCap":"Đại Thiên Tôn","hePhai":"Cửu Đế","soHuu":["Cửu Đế Đại Thiên Tôn"],"blurb":"Thần thông huyễn hóa bạch lang ngoài thân thể của Cửu Đế khi công kích Tiên Hoàng.","detail":"Cửu Đế huyễn hóa một con bạch lang bên ngoài thân thể để đánh Tiên Hoàng. Đòn này bị kéo vào vụ tự bạo thân thể của Tiên Hoàng và góp phần tạo thành xung kích hỗn hợp.","uyLuc":"Dùng để công kích trong giao chiến cấp Đại Thiên Tôn.","congNang":["Huyễn hóa bạch lang ngoài thân thể để phát động công kích @c1893"],"nguoiTu":[{"ten":"Cửu Đế Đại Thiên Tôn","tuChuong":"@c1893","tangDatToi":"Thi triển","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1893","loai":"thi triển","importance":"normal","giaiDoan":"Công kích Tiên Hoàng","text":"Cửu Đế huyễn hóa bạch lang ngoài thân thể khi lao tới đánh Tiên Hoàng.","anchor":"bên ngoài thân thể cũng huyễn hóa ra một con bạch lang"}]},"capNhatToi":"@c1893","nguon":["@c1893"]},{"id":"luc-luong-thai-duong-cua-cuu-de","name":"Lực lượng thái dương của Cửu Đế","cn":"","loai":"than-thong","loaiLabel":"Thần thông Đại Thiên Tôn","phamCap":"Đại Thiên Tôn","hePhai":"","soHuu":["Cửu Đế Đại Thiên Tôn"],"blurb":"Thần thông thái dương Cửu Đế thi triển khi bị Trớ Thuật quấn thân, hiện mặt trời trắng sau lưng và triệu bạch lang công kích.","detail":"Cửu Đế không tiếc khiến Trớ Thuật nặng thêm để phát động lực lượng thái dương, bộc phát bạch quang, hiện mặt trời trắng khổng lồ phía sau và để bạch lang lao xuyên qua thân hình đánh về phía Song Tử.","uyLuc":"Dùng để đối kháng Song Tử Đại Thiên Tôn trong lúc Cửu Đế đang bị Trớ Thuật ảnh hưởng.","congNang":["Hiện mặt trời trắng phía sau Cửu Đế và phóng bạch lang công kích đối thủ @c1894"],"nguoiTu":[{"ten":"Cửu Đế Đại Thiên Tôn","tuChuong":"@c1894","tangDatToi":"Thi triển trong trạng thái bị Trớ Thuật","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1894","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng Song Tử","text":"Cửu Đế phát động lực lượng thái dương, hiện mặt trời trắng phía sau và gọi bạch lang lao ra để đánh Song Tử.","anchor":"bất ngờ ở phía sau có một vầng mặt trời khổng lồ màu trắng hiện ra"}]},"capNhatToi":"@c1894","nguon":["@c1894"]},{"id":"mat-troi-cua-dao-nhat","name":"Mặt trời của Đạo Nhất","cn":"","loai":"than-thong","loaiLabel":"Thần thông Đại Thiên Tôn","phamCap":"Đại Thiên Tôn","hePhai":"","soHuu":["Đạo Nhất Đại Thiên Tôn"],"blurb":"Thần thông mặt trời Đạo Nhất hiện ra khi toàn lực đoạt đầu lâu Tiên Tổ, nhưng bị Trớ Thuật làm suy yếu nặng.","detail":"Đạo Nhất mở mặt trời phía sau trong lúc lao tới đoạt đầu lâu, song do là Đại Thiên Tôn yếu nhất và bị Trớ Thuật quấn nặng, mặt trời trở nên ảm đạm và lực lượng phát ra không nhiều.","dacDiem":"Bị Trớ Thuật áp chế khiến mặt trời phía sau ảm đạm, khó phát huy đầy đủ uy lực.","congNang":["Hiện mặt trời phía sau Đạo Nhất khi hắn toàn lực tham chiến @c1894"],"nguoiTu":[{"ten":"Đạo Nhất Đại Thiên Tôn","tuChuong":"@c1894","tangDatToi":"Thi triển nhưng suy yếu","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1894","loai":"thi triển","importance":"normal","giaiDoan":"Đoạt đầu lâu Tiên Tổ","text":"Đạo Nhất hiện mặt trời phía sau nhưng ánh sáng ảm đạm vì Trớ Thuật trong cơ thể quá nghiêm trọng.","anchor":"mặt trời phía sau ảm đạm không chút ánh sáng"}]},"capNhatToi":"@c1894","nguon":["@c1894"]},{"id":"chien-phap-tac","name":"Chiến pháp tắc","cn":"","loai":"khac","loaiLabel":"Pháp tắc","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Minh ngộ pháp tắc chiến đấu của Vương Lâm, làm bộc phát chiến ý hiếm thấy khi Đạo Nhất áp sát.","detail":"Chiến pháp tắc được nhắc như nguồn chiến ý của Vương Lâm tóc đen trong trận với Đạo Nhất. Minh ngộ này gắn với trải nghiệm của hắn ở động phủ giới.","thuocTinh":"chiến ý","congNang":["Bộc phát chiến ý trên người Vương Lâm tóc đen khi đối mặt Đạo Nhất @c1895"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1895","tangDatToi":"minh ngộ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1895","loai":"nhắc tới","importance":"normal","giaiDoan":"Minh ngộ chiến ý","text":"Chiến pháp tắc được nêu là căn nguyên khiến Vương Lâm tóc đen bộc phát chiến ý khi Đạo Nhất tới gần.","anchor":"Đây là minh ngộ của hắn đối với Chiến pháp tắc ở động phủ giới"}]},"capNhatToi":"@c1895","nguon":["@c1895"]},{"id":"dao-khat","name":"Đạo Khất","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lời gọi chiêu được Vương Lâm hô lên trước khi lấy mảnh vỡ Tiên Cực kiếm và triển khai thế tách bổn nguyên.","detail":"Đạo Khất xuất hiện như một tiếng gầm mở thế của Vương Lâm trên đầu lâu Tiên Tổ. Sau đó hắn gọi ngũ hành chân thân cùng các bổn nguyên ra ngoài để đối đầu Đạo Nhất.","congNang":["Mở màn thế tách bổn nguyên và gọi các lực lượng của Vương Lâm ra ngoài @c1895"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1895","tangDatToi":"thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1895","loai":"thi triển","importance":"normal","giaiDoan":"Mở thế đối chiến","text":"Vương Lâm hô lên khi đứng trên đầu lâu Tiên Tổ, ngay trước lúc lấy mảnh vỡ Tiên Cực kiếm và tách bổn nguyên.","anchor":"Vương Lâm đứng trên đầu lâu của Tiên Tổ, ngửa mặt lên trời gầm nhẹ"}]},"capNhatToi":"@c1895","nguon":["@c1895"]},{"id":"kim-bon-nguyen","name":"Kim bổn nguyên","cn":"","loai":"khac","loaiLabel":"Bổn nguyên ngũ hành","phamCap":"đại thành @c1895","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo bổn nguyên cuối cùng trong ngũ hành của Vương Lâm, đại thành nhờ mảnh vỡ Tiên Cực kiếm.","detail":"Kim bổn nguyên hoàn tất khi mảnh vỡ Tiên Cực kiếm dung nhập vào cơ thể Vương Lâm. Mốc này khiến ngũ hành của hắn viên mãn, dù Kim bổn nguyên chân thân chưa ngưng tụ riêng.","thuocTinh":"kim","congNang":["Hoàn tất đạo bổn nguyên cuối cùng trong ngũ hành của Vương Lâm @c1895","Góp phần khiến ngũ hành chân thân bộc phát lực lượng năm màu @c1895"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1895","tangDatToi":"đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1895","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Đại thành","text":"Kim bổn nguyên đại thành sau khi mảnh vỡ Tiên Cực kiếm dung nhập, hoàn tất ngũ hành của Vương Lâm.","anchor":"đạo bổn nguyên cuối cùng trong ngủ hành của hắn - Kim bổn nguyên đã đại thành"}]},"capNhatToi":"@c1895","nguon":["@c1895"]},{"id":"tro-thuat","name":"Trớ Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Chú thuật","phamCap":"không rõ","hePhai":"","soHuu":[],"blurb":"Lực lượng chú thuật bùng phát trong cơ thể Đạo Nhất, thiêu đốt linh hồn và đẩy hắn vào nguy cơ tử vong.","detail":"Trớ Thuật trong cơ thể Đạo Nhất bùng phát hoàn toàn trong lúc hắn bị Vương Lâm áp chế. Nó dung hợp với sát lục khí và bắt đầu thiêu đốt linh hồn, buộc Đạo Nhất phải bỏ chạy để bế quan điều dưỡng.","congNang":["Thiêu đốt linh hồn Đạo Nhất và tạo nguy cơ sinh tử @c1895"],"tabs":{"tienTrinh":[{"chuong":"@c1895","loai":"thi triển","importance":"normal","giaiDoan":"Bùng phát trong Đạo Nhất","text":"Trớ Thuật bùng phát trong cơ thể Đạo Nhất, khiến hắn sợ chết và phải rời khỏi chiến trường.","anchor":"luồng lực lượng Trớ Thuật này bắt đầu thiêu đốt linh hồn hắn"}]},"capNhatToi":"@c1895","nguon":["@c1895"]},{"id":"dai-thien-ton-chi-duong","name":"Đại Thiên Tôn Chi Dương","cn":"","loai":"khac","loaiLabel":"Dị tượng cấp Đại Thiên Tôn","phamCap":"hình dáng ban đầu @c1895","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đại Thiên Tôn Chi Dương là dị tượng mặt trời nửa đen nửa trắng hiện sau lưng Vương Lâm khi hắn dung hợp chân thân và bổn nguyên, được các Đại Thiên Tôn nhận ra là hình dáng ban đầu của Đại Thiên Tôn Chi Dương chứ không phải ảo ảnh thần thông. (+) Đại Thiên Tôn chi dương là hiển hóa sau lưng Vương Lâm khi hắn dồn sức đối phó tử quang hộ thân của Đạo Cổ hoàng tôn. [CAN-SOAT-GOP]","detail":"Tại chương 1895, sau khi Vương Lâm hoàn thành dung hợp chân thân và bổn nguyên trở lại trạng thái nửa đen nửa trắng, hư ảnh mặt trời Đại Thiên Tôn Chi Dương tự nhiên ngưng tụ sau lưng hắn. Đây là biểu hiện trạng thái cực mạnh hiện thời của Vương Lâm khi chưa có phân thân trong hư vô, và được các Đại Thiên Tôn xác nhận là hình dáng ban đầu thật sự của Đại Thiên Tôn Chi Dương.","hinhDang":"mặt trời nửa đen nửa trắng mơ hồ","dacDiem":"Không phải ảo ảnh thần thông mà là hình dáng ban đầu của Đại Thiên Tôn Chi Dương.","congNang":["Biểu hiện trạng thái cực mạnh hiện thời của Vương Lâm khi chưa có phân thân trong hư vô @c1895","Dấu hiệu cho thấy Vương Lâm tự thân ngưng ra hình dáng ban đầu của Đại Thiên Tôn Chi Dương @c1895"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1895","tangDatToi":"hình dáng ban đầu","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1895","loai":"xuất hiện","importance":"major","giaiDoan":"Hình dáng ban đầu","text":"Sau khi Vương Lâm dung hợp chân thân và bổn nguyên, hư ảnh mặt trời nửa đen nửa trắng hiện sau lưng hắn và được nhận ra là Đại Thiên Tôn Chi Dương.","anchor":"đây không phải là ảo ảnh của thần thông, mà là. Đại Thiên Tôn Chi Dương"}]},"capNhatToi":"@c1895","nguon":["@c1895","@c1920"]},{"id":"bi-thuat-cua-toc-hai-tu","name":"Bí thuật của tộc Hài Tử","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Tộc của Hài Tử","soHuu":["Hài Tử"],"blurb":"Bí thuật được Hài Tử dùng để mở dấu ấn trên Liên Đạo Phi và biến hắn thành sức mạnh trấn áp thay đầu tiên tổ.","detail":"Hài Tử thi triển bí thuật phối hợp tu vi Đại Thiên Tôn của Liên Đạo Phi, khiến hắn tỏa kim quang và trở thành Đại Thiên Tôn ngủ say trấn áp linh hồn bảy mươi hai châu.","thuocTinh":"Trấn áp, truyền thừa","uyLuc":"Có thể phối hợp truyền thừa tiên tổ để hình thành một Đại Thiên Tôn ngủ say làm vật trấn áp.","dacDiem":"Cần đối tượng có huyết mạch và truyền thừa một phần tu vi tiên tổ.","congNang":["Mở dấu ấn trên Liên Đạo Phi và dùng hắn thay đầu tiên tổ trấn áp linh hồn bảy mươi hai châu @c1897"],"nguoiTu":[{"ten":"Hài Tử","tuChuong":"@c1897","tangDatToi":"Thi triển được","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1897","loai":"thi triển","importance":"normal","giaiDoan":"Dùng Liên Đạo Phi thay đầu tiên tổ","text":"Hài Tử dùng bí thuật của tộc mình phối hợp tu vi Đại Thiên Tôn của Liên Đạo Phi để biến hắn thành lực lượng trấn áp bảy mươi hai châu.","anchor":"Với tu vi Đại Thiên Tôn của hắn phối hợp với bí thuật của tộc ta"}]},"capNhatToi":"@c1897","nguon":["@c1897"]},{"id":"luc-luong-tro-thuat-trong-than-cuu-de","name":"Lực lượng Trớ Thuật trong thân Cửu Đế","cn":"","loai":"bi-thuat","loaiLabel":"Trớ thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Cửu Đế"],"blurb":"Lực lượng Trớ Thuật tồn tại trong thân Cửu Đế, được hắn dùng làm áp lực uy hiếp Vương Lâm.","detail":"Cửu Đế từng lấy việc không áp chế Trớ Thuật trong cơ thể để buộc Vương Lâm cân nhắc; cuối chương, hắc khí trên người hắn lan tràn, mơ hồ khó áp chế.","thuocTinh":"Trớ thuật, hắc khí","uyLuc":"Khi mất khống chế có thể lan tràn thành hắc khí trên thân Cửu Đế.","dacDiem":"Khó áp chế và tạo thành đại giá rõ rệt cho người mang nó.","congNang":["Tạo sức ép uy hiếp vì Cửu Đế có thể không áp chế Trớ Thuật trong thân @c1897"],"nguoiTu":[{"ten":"Cửu Đế","tuChuong":"@c1897","tangDatToi":"Mang trong thân","trangThai":"kho-ap-che"}],"tabs":{"tienTrinh":[{"chuong":"@c1897","loai":"nhắc tới","importance":"normal","giaiDoan":"Hắc khí lan tràn","text":"Trớ Thuật trong thân Cửu Đế lan thành hắc khí và mơ hồ không thể áp chế.","anchor":"trên người hắn đã bắt đầu tràn ngập hắc khí, mơ hồ đã không thể áp chế được"}]},"capNhatToi":"@c1897","nguon":["@c1897"]},{"id":"than-thong-cua-dieu-vong-toc","name":"Thần thông của Điệu Vong tộc","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông chủng tộc","phamCap":"không rõ","hePhai":"Điệu Vong tộc","soHuu":["Hài Tử"],"blurb":"Thần thông chủng tộc được Hài Tử dùng để trợ giúp Cửu Đế hóa giải Trớ Thuật sau biến cố hoàng cung.","detail":"Hài Tử thi triển thần thông của Điệu Vong tộc để hỗ trợ Trớ Thuật trong thân Cửu Đế dần tiêu tán theo thời gian.","congNang":["Trợ giúp tiêu tán Trớ Thuật trong cơ thể người bị nguyền rủa @c1898"],"nguoiTu":[{"ten":"Hài Tử","tuChuong":"@c1898","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1898","loai":"thi triển","importance":"normal","giaiDoan":"Trợ Cửu Đế","text":"Hài Tử dùng thần thông Điệu Vong tộc trợ giúp Cửu Đế hóa giải Trớ Thuật.","anchor":"lại có Hải Tử dùng thần thông của Điệu Vong tộc trợ giúp"}]},"capNhatToi":"@c1898","nguon":["@c1898"]},{"id":"kim-bon-nguyen-dai-thanh","name":"Kim bổn nguyên đại thành","cn":"","loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Trạng thái kim bổn nguyên đại thành của Vương Lâm sau khi hấp thu mảnh vỡ Tu Chân Liên Minh.","detail":"Kim bổn nguyên đại thành là một nguyên nhân khiến tu vi Vương Lâm tăng từ Không Kiếp trung kỳ lên Không Kiếp hậu kỳ.","thuocTinh":"kim","congNang":["Giúp tu vi Vương Lâm tăng từ Không Kiếp trung kỳ lên Không Kiếp hậu kỳ @c1900"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1900","tangDatToi":"đại thành","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1900","loai":"nhắc tới","importance":"normal","giaiDoan":"đại thành","text":"Kim bổn nguyên đại thành được xác nhận là nguyên nhân làm tu vi Vương Lâm tăng lên Không Kiếp hậu kỳ.","anchor":"Kim bổn nguyên đại thành khiến tu vi của Vương Lâm bất ngờ từ Không Kiếp trung kỳ tăng lên tới Không Kiếp hậu kỳ"}]},"capNhatToi":"@c1900","nguon":["@c1900"]},{"id":"sat-luc-loi-dinh-chan-than","name":"Sát lục lôi đình chân thân","cn":"","loai":"khac","loaiLabel":"Chân thân bổn nguyên","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đường ngưng tụ chân thân từ nhóm bổn nguyên lôi, sát lục, thái sơ, mặc diệt và cấm chế của Vương Lâm.","detail":"Lôi bổn nguyên của Vương Lâm đã ngưng tụ chân thân, còn sát lục, thái sơ, mặc diệt và cấm chế mới ở mức đại thành. Nếu các bổn nguyên còn lại đều ngưng chân thân, chiến lực của hắn sẽ tăng mạnh.","thuocTinh":"lôi, sát lục, thái sơ, mặc diệt, cấm chế","congNang":["Khi nhiều bổn nguyên ngưng tụ chân thân, chiến lực Vương Lâm sẽ tăng mạnh @c1900"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1900","tangDatToi":"lôi bổn nguyên đã ngưng chân thân","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1900","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"lôi đã ngưng chân thân","text":"Vương Lâm xác định lôi bổn nguyên đã ngưng tụ chân thân, còn sát lục, thái sơ, mặc diệt và cấm chế vẫn cần tiếp tục hoàn thiện.","anchor":"trong đó đã lôi bổn nguyên đã ngưng tụ chân thân, còn lại bốn bổn nguyên là sát lục, thái sơ, mặc diệt, cấm chế"}]},"capNhatToi":"@c1900","nguon":["@c1900"]},{"id":"hu-bon-nguyen","name":"Hư bổn nguyên","cn":"","loai":"khac","loaiLabel":"Bổn nguyên hư","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Hệ hư bổn nguyên mà Vương Lâm cảm ngộ, được hắn nhận định là con đường tiến triển rất chậm nếu chỉ dựa vào cảm ngộ.","detail":"Vương Lâm đã cảm ngộ ba đạo hư bổn nguyên. Hắn nhận định con đường này quá khó và quá chậm, nên tạm đặt trọng điểm tu hành vào việc ngưng tụ chân thân bổn nguyên.","thuocTinh":"hư","congNang":["Cảm ngộ thêm hư bổn nguyên có thể giúp Vương Lâm tiến gần hơn tới mục tiêu vượt Đại Thiên Tôn @c1900"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1900","tangDatToi":"ba đạo đã cảm ngộ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1900","loai":"nhắc tới","importance":"normal","giaiDoan":"ba đạo đã cảm ngộ","text":"Vương Lâm xác định hiện mới có ba hư bổn nguyên và không thể chỉ đi theo con đường này.","anchor":"cả đời ta lúc này mới chỉ cảm ngộ được ba hư bổn nguyên mà thôi"}]},"capNhatToi":"@c1900","nguon":["@c1900"]},{"id":"luan-hoi-hu-bon-nguyen","name":"Luân hồi hư bổn nguyên","cn":"","loai":"khac","loaiLabel":"Hư bổn nguyên","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đạo hư bổn nguyên thứ tư mà Vương Lâm xác định theo minh ngộ ở Đông Lâm tông.","detail":"Vương Lâm cho rằng luân hồi chính là hư bổn nguyên thứ tư hắn cần cảm ngộ, dựa trên minh ngộ từng có ở Đông Lâm tông.","thuocTinh":"luân hồi","congNang":["Là hư bổn nguyên thứ tư trong hướng cảm ngộ của Vương Lâm @c1900"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1900","tangDatToi":"định hướng cảm ngộ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1900","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"đạo thứ tư","text":"Vương Lâm xác định luân hồi là hư bổn nguyên thứ tư theo minh ngộ ở Đông Lâm tông.","anchor":"Dựa theo minh ngộ của ta ở Đông Lâm tông, luân hồi chính là hư bổn nguyên thứ tư"}]},"capNhatToi":"@c1900","nguon":["@c1900"]},{"id":"huyet-mach-co-toc-cua-vuong-lam","name":"Huyết mạch cổ tộc của Vương Lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Huyết mạch","phamCap":"Không rõ","hePhai":"Cổ tộc","soHuu":["Vương Lâm"],"blurb":"Huyết mạch cổ tộc trong cơ thể Vương Lâm cộng minh với lực lượng trong hắc thổ cổ tộc. Cảm ứng này xuất hiện khi hắn đặt chân tới đất cổ tộc.","detail":"Khi nắm đất đen cổ tộc, Vương Lâm cảm nhận trong đất có lực lượng khiến huyết mạch cổ tộc trong cơ thể rung động, xác nhận sự liên hệ của hắn với vùng đất này.","thuocTinh":"Cổ tộc","dacDiem":"Cộng minh với lực lượng trong hắc thổ cổ tộc.","congNang":["Khi Vương Lâm nắm đất đen cổ tộc, huyết mạch trong cơ thể hắn rung động vì lực lượng trong đất @c1901"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1901","tangDatToi":"cộng minh huyết mạch","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1901","loai":"nhắc tới","importance":"normal","giaiDoan":"Cộng minh hắc thổ","text":"Huyết mạch cổ tộc trong cơ thể Vương Lâm rung động khi hắn nắm đất đen cổ tộc.","anchor":"có một lực lượng khiến cho huyết mạch cổ tộc trong cơ thể hắn rung động"}]},"capNhatToi":"@c1901","nguon":["@c1901"]},{"id":"cuu-tinh-co-than-cua-vuong-lam","name":"Cửu tinh cổ Thần của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thân phận cổ Thần","phamCap":"Cửu tinh","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Dấu hiệu chín tinh điểm cổ Thần trên mi tâm Vương Lâm. Khi hiển lộ tại Hắc Thạch Thành, nó khiến binh sĩ cổ tộc lập tức kính sợ và xưng hắn là thần thánh đại nhân.","detail":"Vương Lâm hiện chín tinh điểm trên mi tâm trước hai đại hán Cổ Thần đang chất vấn. Các binh sĩ liền đổi thái độ, hành lễ cung kính, cho thấy cửu tinh cổ Thần có địa vị đặc biệt trong cổ tộc.","thuocTinh":"Cổ Thần","uyLuc":"Tạo uy thế thân phận đủ khiến binh sĩ Hắc Thạch Thành kính sợ.","dacDiem":"Cửu tinh cổ Thần được binh sĩ gọi bằng danh xưng thần thánh đại nhân.","congNang":["Hiển lộ chín tinh điểm trên mi tâm để biểu thị thân phận cửu tinh cổ Thần @c1901","Khiến binh sĩ Hắc Thạch Thành kính sợ và hành lễ xưng thần thánh đại nhân @c1901"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1901","tangDatToi":"cửu tinh","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1901","loai":"thi triển","importance":"normal","giaiDoan":"Hiển lộ tại Hắc Thạch Thành","text":"Vương Lâm hiển lộ chín tinh điểm cổ Thần trước binh sĩ Hắc Thạch Thành và được họ kính sợ.","anchor":"trên mi tâm chậm rãi hiện ra chín tinh điểm"}]},"capNhatToi":"@c1901","nguon":["@c1901"]},{"id":"tam-co-cuu-tinh-cua-vuong-lam","name":"Tam cổ cửu tinh của Vương Lâm","cn":"","aliases":[],"loai":"luyen-the","loaiLabel":"Thân thể cổ tộc","phamCap":"Cửu tinh toàn bộ tam cổ","hePhai":"Cổ tộc","soHuu":["Vương Lâm"],"blurb":"Tam cổ cửu tinh là trạng thái thân thể cổ tộc của Vương Lâm khi đạt cửu tinh ở cả ba hệ cổ Thần, cổ Yêu và cổ Ma. Hắn rất ít khi hiển lộ toàn bộ sức mạnh này.","detail":"Theo năm tháng tu luyện, thân thể cổ tộc của Vương Lâm lần lượt đạt tới cửu tinh của cả ba hệ cổ tộc — cổ Thần, cổ Yêu và cổ Ma. Đây là trạng thái nền tảng cực kỳ hiếm, được xác nhận tại chương 1901; tuy nhiên Vương Lâm rất ít khi hiển lộ đầy đủ sức mạnh tam cổ cửu tinh trước mặt người khác.","thuocTinh":"Cổ Thần, cổ Yêu, cổ Ma","dacDiem":"Đồng thời đạt cửu tinh của cả ba hệ cổ tộc.","congNang":["Cho phép Vương Lâm sở hữu nền tảng cửu tinh của toàn bộ tam cổ (cổ Thần, cổ Yêu, cổ Ma) @c1901"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1901","tangDatToi":"cửu tinh toàn bộ tam cổ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1901","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Cửu tinh toàn bộ tam cổ","text":"Chương xác nhận Vương Lâm đã đạt cửu tinh của cả cổ Thần, cổ Yêu và cổ Ma.","anchor":"hắn đã đạt được cửu tinh của toàn bộ tam cổ"}]},"capNhatToi":"@c1901","nguon":["@c1901"]},{"id":"phong-an-van-co-bao-ho-co-hoang","name":"Phong ấn vạn cổ bảo hộ cổ hoàng","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Phong ấn","phamCap":"Vạn cổ","hePhai":"Cổ tộc","soHuu":["Cổ tộc"],"blurb":"Phong ấn vạn cổ bảo hộ cổ hoàng là trật tự cố hữu của cổ tộc,ràng buộc Đại Thiên Tôn cổ tộc không được vì bất cứ nguyên nhân nào gây tổn thương cho cổ hoàng. Phong ấn này gắn liền với sự bảo hộ củaổ tam mạch và người có khả năng trở thành cổ hoàng.","detail":"Phong ấn vạn cổ bắt nguồn từ trật tự vạn cổ của cổ tộc, được thiết lập nhằm bảo vệ hoàng quyền tuyệt đối. Dù Đại Thiên Tôn cổ tộc sở hữu tu vi tối cao, họ vẫn không thể lật đổ hay làm tổn thương cổ hoàng khi phong ấn còn tồn tại. Phong ấn liên hệ mật thiết với sự bảo hộ của cổ tam mạch cùng Đại Thiên Tôn mạnh nhất tại thánh địa cổ tộc, đảm bảo ngôi vị cổ hoàng bất khả xâm phạm.","thuocTinh":"Phong ấn, quy tắc hoàng quyền","nguonGoc":"Trật tự vạn cổ của cổ tộc","uyLuc":"Ngăn Đại Thiên Tôn cổ tộc làm tổn thương cổ hoàng, bất kể tu vi hay lý do.","dacDiem":"Gắn với sự bảo hộ cổ tam mạch và người có khả năng trở thành cổ hoàng.","congNang":["Ngăn Đại Thiên Tôn cổ tộc vì bất cứ nguyên nhân nào làm tổn thương cổ hoàng @c1901"],"tabs":{"tienTrinh":[{"chuong":"@c1901","loai":"xuất hiện","importance":"major","giaiDoan":"Quy tắc bảo hộ cổ hoàng","text":"Chương hé lộ phong ấn vạn cổ bảo hộ cổ hoàng, giới hạn hành động của Đại Thiên Tôn cổ tộc đối với hoàng quyền.","anchor":"cũng sẽ không vì bất cứ một nguyên nhân gì mà làm tổn thương cổ hoàng"}]},"capNhatToi":"@c1901","nguon":["@c1901"]},{"id":"dung-yeu-luyen-ma","name":"Dung yêu luyện ma","cn":"","loai":"khac","loaiLabel":"Giai đoạn tu luyện","phamCap":"Sau đệ nhị tôn","hePhai":"Cổ tộc","soHuu":["Lương Vân","Mạch Lạc"],"blurb":"Dung yêu luyện ma là giai đoạn tu luyện cổ tộc được Lương Vân nhắc tới khi xét Vương Lâm đã vượt qua đệ nhị tôn. Mạch Lạc cho rằng Vương Lâm chưa có khí tức yêu ma nên chưa thật sự vượt qua giai đoạn này.","detail":"Khái niệm này gắn với con đường sau đệ nhị tôn của nhóm thần thánh, yêu thánh và ma thánh. Chương 1902 chỉ hé lộ rằng nó liên quan tới khí tức yêu ma và khiến Vương Lâm chấn động vì mới nghe tới.","thuocTinh":"Yêu ma","dacDiem":"Liên quan tới giai đoạn sau đệ nhị tôn của tu luyện cổ tộc.","congNang":["Dùng để chỉ giai đoạn tu luyện liên quan yêu ma sau khi vượt qua đệ nhị tôn @c1902"],"nguoiTu":[{"ten":"Lương Vân","tuChuong":"@c1902","tangDatToi":"Đã biết khái niệm","trangThai":"đang tu"},{"ten":"Mạch Lạc","tuChuong":"@c1902","tangDatToi":"Đã biết khái niệm","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1902","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ sau đệ nhị tôn","text":"Lương Vân cho rằng Vương Lâm sau khi vượt qua đệ nhị tôn hẳn đã tới giai đoạn dung yêu luyện ma, còn Mạch Lạc dùng khí tức yêu ma để bình phẩm hắn.","anchor":"Vương huynh cũng là thần thánh đã vượt qua đệ nhị tôn, hẳn là tới giai đoạn dung yêu luyện ma"}]},"trangThai":"Đã hé lộ","capNhatToi":"@c1902","nguon":["@c1902"]},{"id":"thong-dung-luyen","name":"Thông, dung, luyện","cn":"","loai":"khac","loaiLabel":"Hệ thống tu luyện","phamCap":"Không rõ","hePhai":"Cổ tộc","soHuu":["Lương Vân","Mạch Lạc"],"blurb":"Thông, dung, luyện là hệ thống hoặc ba giai đoạn tu luyện cổ tộc được Mạch Lạc và Lương Vân nhắc tới. Cả hai đều cho thấy việc vượt qua các bước này rất khó.","detail":"Trong chương 1902, thông, dung, luyện được nêu như mạch tu luyện mà người bản địa cổ tộc hiểu rõ, còn Vương Lâm lần đầu nghe nên nội tâm chấn động. Nội dung chi tiết từng bước chưa được giải thích đầy đủ.","dacDiem":"Rất khó vượt qua, liên quan tới khí tức yêu ma và giai đoạn sau đệ nhị tôn.","congNang":["Dùng để phân chia tiến trình tu luyện cổ tộc mà thần thánh, yêu thánh, ma thánh nhắc tới @c1902"],"nguoiTu":[{"ten":"Lương Vân","tuChuong":"@c1902","tangDatToi":"Đã biết khái niệm","trangThai":"đang tu"},{"ten":"Mạch Lạc","tuChuong":"@c1902","tangDatToi":"Đã biết khái niệm","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1902","loai":"xuất hiện","importance":"normal","giaiDoan":"Ba bước khó vượt","text":"Mạch Lạc và Lương Vân cùng nhắc thông, dung, luyện như ba bước khó trong tu luyện cổ tộc.","anchor":"Thông, dung, luyện thật khó khăn, há có thể dễ dàng vượt qua"}]},"trangThai":"Đã hé lộ","capNhatToi":"@c1902","nguon":["@c1902"]},{"id":"trong-suot-hoa-than","name":"Trong suốt hóa thân","aliases":["xuyên chụp của Vương Lâm"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn khiến Vương Lâm như trở nên trong suốt trước cú chụp của Cổ Yêu. Khổng Ti quan sát thấy biểu hiện này không phải yêu lực thông thường.","detail":"Khi bàn tay Cổ Yêu chụp xuống, thân ảnh Vương Lâm như trong suốt, khiến cú đánh chồng lên người hắn mà không thật sự chạm được. Đây là thủ đoạn né tránh công kích mạnh, chưa được nêu tên chính thức trong chương.","thuocTinh":"thân pháp hoặc thần thông né tránh","uyLuc":"Có thể khiến cú chụp của Đại Cổ Yêu không chạm được Vương Lâm.","dacDiem":"Biểu hiện như thân thể trong suốt và không có yêu lực lan ra theo quan sát của Khổng Ti.","congNang":["Né công kích Cổ Yêu bằng trạng thái như trong suốt @c1903"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1903","tangDatToi":"chưa rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1903","loai":"thi triển","importance":"normal","giaiDoan":"tránh cú chụp Cổ Yêu","text":"Vương Lâm khiến bàn tay Cổ Yêu chụp trượt qua thân ảnh như trong suốt.","anchor":"Cũng có thể nói là Vương Lâm trở nên trong suốt"}]},"capNhatToi":"@c1903","nguon":["@c1903"]},{"id":"uy-ap-anh-mat-cua-vuong-lam","name":"Uy áp ánh mắt của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Uy áp thần thông","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":["Vương Lâm"],"blurb":"Uy áp phát ra qua ánh mắt và lời nói của Vương Lâm. Một ánh mắt khiến Cổ Yêu sợ hãi quỳ phục, đồng thời ép Diệp Hải cùng sứ đoàn Đạo Cổ chịu áp lực nặng nề.","detail":"Vương Lâm chỉ quay đầu nhìn và hỏi một câu đã khiến Cổ Yêu đang điên cuồng cảm nhận tử vong, kêu thảm rồi quỳ bái. Uy áp của hắn sau đó tiếp tục khiến Diệp Hải cùng những người trên đầu Cổ Ma phải lui lại, bộc phát lực lượng chống đỡ.","thuocTinh":"uy áp tinh thần và huyết mạch","uyLuc":"Áp chế Đại Cổ Yêu và tu sĩ Đạo Cổ có hai mươi bảy tinh điểm.","dacDiem":"Có thể làm đối tượng sụp đổ ý chí chỉ bằng ánh mắt.","congNang":["Áp chế Cổ Yêu bằng ánh mắt và lời nói @c1903","Gây áp lực khiến Diệp Hải và sứ đoàn Đạo Cổ phải lui lại @c1903"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1903","tangDatToi":"chưa rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1903","loai":"thi triển","importance":"normal","giaiDoan":"áp phục Cổ Yêu và sứ đoàn","text":"Vương Lâm dùng ánh mắt và uy áp khiến Cổ Yêu quỳ phục, sau đó ép Diệp Hải cùng sứ đoàn Đạo Cổ kinh hãi.","anchor":"Giống như ánh mắt của Vương Lâm có thể khiến nó sụp đổ"}]},"capNhatToi":"@c1903","nguon":["@c1903"]},{"id":"dung-hop-hai-muoi-bay-tinh","name":"Dung hợp hai mươi bảy tinh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Cổ Tộc","hePhai":"Cổ Tộc","soHuu":["Đại Cổ Yêu của Kế Đô"],"blurb":"Nghi thức hoặc phương thức tu luyện của Cổ Tộc nhằm đạt sự thừa nhận của Cổ Tổ. Trường hợp Đại Cổ Yêu của Kế Đô thất bại dẫn tới thoái hóa thành yêu thể mất thần trí.","detail":"Đại Cổ Yêu của Kế Đô khi còn là chiến sĩ cấm vệ Thủy Cổ từng dung hợp hai mươi bảy tinh nhưng thất bại trong việc được Cổ Tổ thừa nhận. Hậu quả được nêu rõ là thoái hóa trở thành yêu thể và mất thần trí.","thuocTinh":"Cổ Tộc","yeuCau":"Dung hợp hai mươi bảy tinh","uyLuc":"Có liên quan tới việc tranh thủ sự thừa nhận của Cổ Tổ.","dacDiem":"Thất bại có thể khiến người tu thoái hóa thành yêu thể và mất thần trí.","trangThai":"đã hé lộ","nguoiTu":[{"ten":"Đại Cổ Yêu của Kế Đô","tuChuong":"@c1904","tangDatToi":"dung hợp hai mươi bảy tinh nhưng thất bại","trangThai":"thoái hóa mất thần trí"}],"congNang":["Thử đạt sự thừa nhận của Cổ Tổ @c1904"],"tabs":{"tienTrinh":[{"chuong":"@c1904","loai":"xuất hiện","importance":"normal","giaiDoan":"Lai lịch Đại Cổ Yêu","text":"Kế Đô hé lộ Đại Cổ Yêu từng dung hợp hai mươi bảy tinh nhưng thất bại trong việc được Cổ Tổ thừa nhận nên thoái hóa mất thần trí.","anchor":"sau khi dung hợp hai mươi bảy tinh, thất bại trong việc đạt được sự thừa nhận của Cổ Tổ"}]},"capNhatToi":"@c1904","nguon":["@c1904"]},{"id":"cam-che-phong-ho-dao-co-hoang-thanh","name":"Cấm chế phòng hộ Đạo Cổ hoàng thành","cn":"","loai":"khac","loaiLabel":"trận pháp/cấm chế","phamCap":"không rõ","hePhai":"Đạo Cổ nhất mạch","soHuu":["Đạo Cổ nhất mạch"],"blurb":"Lớp phòng hộ nghiêm mật bao quanh Thiên Không Thành, hình thành cùng đá vụn xoay tròn bên ngoài thành. Người thường cần ngọc giản thân phận mới có thể vào thành.","detail":"Cấm chế bao phủ bên ngoài Thiên Không Thành của Đạo Cổ hoàng thành, ngăn người không có thân phận bước vào. Theo nhận thức của tộc nhân Đạo Cổ, chỉ Tiên Cương Cửu Dương mới có thể tự do ra vào ba hoàng thành Cổ Tộc, nhưng Vương Lâm xuyên qua lớp này mà không bị ngăn.","thuocTinh":"phòng hộ hoàng thành","congNang":["Kiểm soát lối vào Đạo Cổ hoàng thành, buộc người vào thành phải có ngọc giản thân phận @c1906"],"trangThai":"đang vận hành","capNhatToi":"@c1906","tabs":{"tienTrinh":[{"chuong":"@c1906","loai":"xuất hiện","importance":"normal","giaiDoan":"phòng hộ Thiên Không Thành","text":"Cấm chế phòng hộ Đạo Cổ hoàng thành được mô tả là tầng phòng hộ nghiêm mật quanh Thiên Không Thành, nhưng không ngăn được Vương Lâm xuyên qua.","anchor":"Ở bên ngoài Thiên Không Thành này, đám đá vụn xoay tròn hợp thành một tầng cấm chế phòng hộ nghiêm mật."}]},"nguon":["@c1906"]},{"id":"tu-khi-hoang-cung-dao-co","name":"Tử khí hoàng cung Đạo Cổ","cn":"","loai":"khac","loaiLabel":"khí tượng/cấm chế hộ cung","phamCap":"không rõ","hePhai":"Hoàng quyền Đạo Cổ","soHuu":["Hoàng quyền Đạo Cổ"],"blurb":"Tử khí bao phủ hoàng cung Đạo Cổ, tạo áp lực mạnh và bảo vệ khu vực trung tâm hoàng quyền. Trong mắt Vương Lâm, tử khí mơ hồ ngưng thành thân ảnh đội vương miện.","detail":"Tử khí bên ngoài hoàng cung Thiên Không Thành ngưng tụ thành hình ảnh khổng lồ đội vương miện, tỏa khí tức Cổ Tộc tinh thuần. Nó đi cùng cấm chế dày đặc, khiến hoàng cung Đạo Cổ có áp lực còn mạnh hơn nơi Vương Lâm từng thấy ở Tiên Tộc.","thuocTinh":"tử khí Cổ Tộc","congNang":["Bao phủ và gia tăng uy áp phòng hộ quanh hoàng cung Đạo Cổ @c1906"],"dacDiem":"Mơ hồ ngưng tụ thành thân ảnh khổng lồ đội vương miện bên ngoài hoàng cung.","trangThai":"đang bao phủ hoàng cung","capNhatToi":"@c1906","tabs":{"tienTrinh":[{"chuong":"@c1906","loai":"xuất hiện","importance":"normal","giaiDoan":"khí tượng hộ cung","text":"Tử khí ngoài hoàng cung Đạo Cổ được Vương Lâm nhìn thấy như thân ảnh đội vương miện, biểu hiện uy áp trung tâm hoàng quyền.","anchor":"tử khí bên ngoài hoàng cung của Thiên Không Thành mơ hồ ngưng tụ lại thành một thân ảnh."}]},"nguon":["@c1906"]},{"id":"khai-linh-tinh-than-the","name":"Khai linh tính, thân thể","cn":"","loai":"khac","loaiLabel":"pháp môn chỉ dẫn tu luyện","phamCap":"không rõ","hePhai":"Đạo Cổ nhất mạch","soHuu":["Chín cường giả Đạo Cổ đi theo đầu lâu Tiên Tổ"],"blurb":"Pháp môn hoặc hình thức chỉ dẫn do chín cường giả Đạo Cổ luân phiên thực hiện tại Đạo Cổ Điện. Nó giúp tộc nhân Đạo Cổ tìm cơ hội đột phá qua việc khai mở linh tính và thân thể.","detail":"Đạo Cổ Điện mở cửa cho mỗi tộc nhân Đạo Cổ muốn tìm cơ hội đột phá, nhưng không phải ai cũng gặp Huyền La. Chín cường giả Đạo Cổ từng đi theo đầu lâu Tiên Tổ thay nhau trấn ở điện, khai linh tính và thân thể cho tộc nhân.","thuocTinh":"hỗ trợ đột phá Cổ Tộc","congNang":["Khai mở linh tính và thân thể cho tộc nhân Đạo Cổ tìm cơ hội đột phá @c1906"],"trangThai":"được thực hiện tại Đạo Cổ Điện","capNhatToi":"@c1906","tabs":{"tienTrinh":[{"chuong":"@c1906","loai":"xuất hiện","importance":"normal","giaiDoan":"chỉ dẫn tại Đạo Cổ Điện","text":"Chín cường giả Đạo Cổ luân phiên ở Đạo Cổ Điện để khai linh tính và thân thể cho tộc nhân.","anchor":"Chín người này bất cứ lúc nào cũng có một người tồn tại trong Đạo Cổ Điện, khai linh tính, thân thể cho tộc nhân!"}]},"nguon":["@c1906"]},{"id":"cam-che-phong-an-dam-lay-binh-thien-quan","name":"Cấm chế phong ấn đầm lầy Bình Thiên Quận","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp, cấm chế","phamCap":"Không rõ","hePhai":"Đạo Cổ nhất mạch","soHuu":["Đại Thiên Tôn đời thứ nhất của Đạo Cổ nhất mạch"],"blurb":"Cấm chế do Đại Thiên Tôn đời thứ nhất Đạo Cổ bố trí để bảo tồn đầm lầy cổ chiến trường ở Bình Thiên Quận.","detail":"Cấm chế phong ấn này giữ đầm lầy cổ chiến trường nguyên vẹn qua thời gian, về sau trở thành nơi Huyền La đưa Vương Lâm tới để tu hành sát lục bản nguyên.","congNang":["Bảo tồn đầm lầy cổ chiến trường nguyên vẹn trong phong ấn (@c1908)"],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1908","loai":"xuất hiện","importance":"normal","giaiDoan":"Đầm lầy Bình Thiên Quận","text":"Cấm chế được nhắc là do Đại Thiên Tôn đời thứ nhất Đạo Cổ bố trí để bảo tồn đầm lầy nguyên vẹn.","anchor":"còn bố trí cấm chế phong ấn, khiến cho nó được bảo tồn nguyên vẹn"}]},"capNhatToi":"@c1908","nguon":["@c1908"]}]};
